import { GoogleGenAI } from "@google/genai";

export const createAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to clean AI output
const cleanHtmlOutput = (text: string): string => {
  if (!text) return "";
  // Remove markdown code blocks (```html ... ```)
  return text
    .replace(/^```html\s*/i, '') // Remove start block
    .replace(/^```\s*/i, '')     // Remove start block generic
    .replace(/\s*```$/i, '')      // Remove end block
    .trim();                      // Trim whitespace
};

// Generate Detailed Content directly from a Topic
export const generateTopicContent = async (
  topic: string,
  language: string
): Promise<string> => {
  const ai = createAIClient();

  const prompt = `
    You are an expert book writer.
    **Topic:** "${topic}"
    **Language:** ${language}

    **Task:** Write a comprehensive guide.

    **Structure Rules (Strict):**
    1. Use **Hierarchical Decimal Numbering** (1. Title, 1.1 Sub-topic, 1.1.1 Detail).
    2. Use HTML tags: <h1>, <h2>, <h3>, <p>, <ul>, <li>, <table>.

    **Visuals:**
    - Create at least one **SVG Diagram** inside a <div class="flowchart-container">.
    - Use Tailwind classes for tables (border-collapse border border-black w-full mb-4).

    **Output:** Return ONLY raw HTML. No markdown formatting.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", 
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 2048 }
    }
  });

  return cleanHtmlOutput(response.text || "");
};

// Generate Structured Notes from Raw Text
export const generateFormattedNotes = async (
  rawText: string,
  language: string
): Promise<string> => {
  const ai = createAIClient();

  const prompt = `
    You are an expert formatter. 
    **Task:** Structure the provided text into a formal document with Decimal Headings (1.0, 1.1).
    **Language:** ${language}

    **Input:** ${rawText}

    **Requirements:**
    - Use <h1>, <h2>, <h3>.
    - Create HTML tables for data.
    - Create SVG diagrams where appropriate (Process/Hierarchy).
    - Return ONLY raw HTML.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 2048 }
    }
  });

  return cleanHtmlOutput(response.text || "");
};

// Rewrite specific text selection
export const rewriteContent = async (
    textToRewrite: string,
    instruction: string
  ): Promise<string> => {
    const ai = createAIClient();

    const prompt = `
      You are an expert editor.
      **Input:** "${textToRewrite}"
      **Instruction:** ${instruction}

      **Task:** Rewrite the text. Return ONLY the HTML fragment. Do not wrap in markdown.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });

    return cleanHtmlOutput(response.text || textToRewrite);
};

// Mode 1: REWRITE (Small edits)
export const rewriteSection = async (
  sectionContent: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();
  const prompt = `
    You are an expert editor.
    **Task:** Rewrite the HTML section below based on the instruction.
    **Constraint:** Keep the structure (headings/paragraphs) valid.

    **HTML:** ${sectionContent}
    **Instruction:** "${instruction}"

    **Output:** Return ONLY the valid HTML.
  `;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
  });
  return cleanHtmlOutput(response.text || "");
};

// Mode 2: EXPAND (Deep Dive)
export const expandSection = async (
  sectionContent: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();
  const prompt = `
    You are an expert book writer.
    **Task:** EXPAND the following section into a detailed explanation (1-2 pages).

    **Input HTML:**
    ${sectionContent}

    **Instruction:** "${instruction}"

    **Rules:**
    - If the input lists items (e.g. "Article 14, 15"), create SUB-HEADINGS for each (e.g. <h3>2.1.1 Article 14</h3>).
    - Add examples and detailed paragraphs.
    - Maintain hierarchy.

    **Output:** Return ONLY the valid HTML.
  `;
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 1024 }
    }
  });
  return cleanHtmlOutput(response.text || "");
};

// Mode 3: CONTINUE (Add next content)
export const generateNextContent = async (
  previousContext: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();
  const prompt = `
    You are an expert book writer.
    **Context:** The user wants to continue writing AFTER this section.

    **Previous Section:**
    ${previousContext}

    **Instruction:** "${instruction}"

    **Task:** Write the NEXT logical content (next headings, next chapters).
    **Output:** Return ONLY the HTML for the NEW content.
  `;
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 1024 }
    }
  });
  return cleanHtmlOutput(response.text || "");
};

