import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  generateTopicContent, 
  generateFormattedNotes, 
  rewriteContent, 
  rewriteSection,
  expandSection,
  generateNextContent
} from './services/ai';
import { GenerationStatus } from './types';
import { Button } from './components/Button';
import { 
  BookOpen, 
  PenTool, 
  Printer, 
  Sparkles,
  FileText,
  Trash2,
  Wand2,
  ArrowLeft,
  Check,
  Save,
  Undo,
  Redo,
  RefreshCw,
  Plus
} from 'lucide-react';

const STORAGE_KEY = 'ai_book_writer_draft';

const App: React.FC = () => {
  // Mode State
  const [mode, setMode] = useState<'topic' | 'text'>('topic');

  // Shared State
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [language, setLanguage] = useState('Hindi'); // Default Hindi
  const [isEditing, setIsEditing] = useState(false);
  const editorRef = useRef<HTMLDivElement>(null);

  // History State for Undo/Redo
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const historyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Lock for Resetting
  const isResettingRef = useRef(false);

  // Rewrite State
  const [rewriteModalOpen, setRewriteModalOpen] = useState(false);
  const [rewriteInstruction, setRewriteInstruction] = useState('');
  const [isRewriting, setIsRewriting] = useState(false);

  // Ref for "Selection" rewrite (highlighted text)
  const selectionRangeRef = useRef<Range | null>(null);

  // Ref for "Section" rewrite (ID tracking)
  const activeEditIdRef = useRef<string | null>(null);
  const [activeSectionHtml, setActiveSectionHtml] = useState<string>('');
  const [rewriteType, setRewriteType] = useState<'selection' | 'section'>('selection');

  // Tabs for Section Editing
  const [editTab, setEditTab] = useState<'rewrite' | 'expand' | 'continue'>('rewrite');

  // Content State
  const [generatedHtml, setGeneratedHtml] = useState<string | null>(null);

  // Inputs
  const [topicInput, setTopicInput] = useState('');
  const [textInput, setTextInput] = useState('');

  // --- HISTORY MANAGEMENT ---

  const pushToHistory = useCallback((content: string) => {
    setHistory(prev => {
      // If content is same as current tip, don't push
      if (historyIndex >= 0 && prev[historyIndex] === content) {
        return prev;
      }
      // Slice history if we are in middle of stack
      const newHistory = prev.slice(0, historyIndex + 1);
      return [...newHistory, content];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      const content = history[newIndex];
      setGeneratedHtml(content);
      setHistoryIndex(newIndex);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      const content = history[newIndex];
      setGeneratedHtml(content);
      setHistoryIndex(newIndex);
    }
  };

  // --- PERSISTENCE & AUTO-SAVE ---

  // 1. Load from Storage on Mount ONLY
  useEffect(() => {
    const savedContent = localStorage.getItem(STORAGE_KEY);
    if (savedContent) {
      setGeneratedHtml(savedContent);
      setHistory([savedContent]);
      setHistoryIndex(0);
    }
  }, []);

  // 2. Helper to get RAW HTML (matches DOM exactly, includes edit buttons)
  const getCurrentHtml = useCallback(() => {
    return editorRef.current ? editorRef.current.innerHTML : (generatedHtml || '');
  }, [generatedHtml]);

  // 3. Helper to get CLEAN HTML (removes buttons/markers)
  const getCleanHtml = useCallback(() => {
    if (!editorRef.current) return generatedHtml || '';

    const clone = editorRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll('.ai-edit-trigger').forEach(b => b.remove());
    clone.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    return clone.innerHTML;
  }, [generatedHtml]);

  // 4. Save Function (Saves Clean Version)
  const saveToStorage = useCallback(() => {
    if (isResettingRef.current) return; // Don't save if resetting
    const content = getCleanHtml();
    if (content) {
      localStorage.setItem(STORAGE_KEY, content);
    }
    return content;
  }, [getCleanHtml]);

  // 5. Event Listeners
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        saveToStorage();
      }
    };

    const intervalId = setInterval(() => {
      if (isEditing) saveToStorage();
    }, 5000);

    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('pagehide', saveToStorage);
    window.addEventListener('beforeunload', saveToStorage);

    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', saveToStorage);
      window.removeEventListener('beforeunload', saveToStorage);
      clearInterval(intervalId);
    };
  }, [saveToStorage, isEditing]);

  // 6. Live Input Handler
  const handleEditorInput = () => {
    if (isResettingRef.current) return;

    if (historyTimeoutRef.current) {
      clearTimeout(historyTimeoutRef.current);
    }

    historyTimeoutRef.current = setTimeout(() => {
       if (isResettingRef.current) return;
       const rawContent = getCurrentHtml(); 
       setGeneratedHtml(rawContent); 
       pushToHistory(rawContent);
       saveToStorage();
    }, 800);
  };

  const handleEditorBlur = () => {
      if (isResettingRef.current) return;
      const rawContent = getCurrentHtml();
      setGeneratedHtml(rawContent);
  };

  // --- HELPER: Identify Section Nodes ---
  const getSectionNodes = (startNode: Element): Element[] => {
    const nodes: Element[] = [startNode];
    const tagName = startNode.tagName;

    const getLevel = (tag: string) => {
      const t = tag.toUpperCase();
      if (t === 'H1') return 1;
      if (t === 'H2') return 2;
      if (t === 'H3') return 3;
      if (t === 'H4') return 4;
      return 10; // Regular text
    };

    const currentLevel = getLevel(tagName);

    if (currentLevel <= 4) {
      let nextSibling = startNode.nextElementSibling;
      while (nextSibling) {
        const nextTag = nextSibling.tagName;
        const nextLevel = getLevel(nextTag);
        if (nextLevel <= currentLevel) break;
        nodes.push(nextSibling);
        nextSibling = nextSibling.nextElementSibling;
      }
    } 
    return nodes;
  };

  // --- SMART EDIT BUTTON LOGIC ---
  useEffect(() => {
    if (!editorRef.current) return;

    if (isEditing) {
      const elements = editorRef.current.querySelectorAll('h1, h2, h3, h4, li');
      elements.forEach((el) => {
        if (el.querySelector('.ai-edit-trigger')) return;

        const btn = document.createElement('span');
        btn.contentEditable = "false";
        btn.className = "ai-edit-trigger no-print";
        btn.innerHTML = "✨";
        btn.title = "Rewrite/Expand this section";

        if (el.tagName === 'LI') {
           el.insertBefore(btn, el.firstChild);
        } else {
           el.appendChild(btn);
        }
      });
    } else {
      const buttons = editorRef.current.querySelectorAll('.ai-edit-trigger');
      buttons.forEach(btn => btn.remove());
    }
  }, [isEditing, generatedHtml]);

  useEffect(() => {
    const handleEditorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.classList.contains('ai-edit-trigger')) {
        e.preventDefault();
        e.stopPropagation();

        const parentEl = target.parentElement;
        if (parentEl) {
          handleSectionEdit(parentEl);
        }
      }
    };

    const editor = editorRef.current;
    if (editor) {
      editor.addEventListener('click', handleEditorClick);
    }
    return () => {
      if (editor) editor.removeEventListener('click', handleEditorClick);
    };
  }, [isEditing]);

  const handleSectionEdit = (startNode: Element) => {
    if (!editorRef.current) return;

    const currentRaw = getCurrentHtml();
    pushToHistory(currentRaw);
    setGeneratedHtml(currentRaw);

    const editId = `edit-${Date.now()}`;
    editorRef.current.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    startNode.setAttribute('data-edit-id', editId);
    activeEditIdRef.current = editId;

    const nodes = getSectionNodes(startNode);

    const tempDiv = document.createElement('div');
    nodes.forEach(node => {
        const clone = node.cloneNode(true) as Element;
        const trigger = clone.querySelector('.ai-edit-trigger');
        if(trigger) trigger.remove();
        clone.removeAttribute('data-edit-id'); 
        tempDiv.appendChild(clone);
    });

    setActiveSectionHtml(tempDiv.innerHTML);
    setGeneratedHtml(editorRef.current.innerHTML); // Sync state

    setRewriteType('section');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  // --- STANDARD HANDLERS ---

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'topic' && !topicInput.trim()) return;
    if (mode === 'text' && !textInput.trim()) return;

    setStatus(GenerationStatus.GENERATING_CHAPTER);

    try {
      let result = "";
      if (mode === 'topic') {
        result = await generateTopicContent(topicInput, language);
      } else {
        result = await generateFormattedNotes(textInput, language);
      }

      // Check if user reset app while generating
      if (isResettingRef.current) return;

      setGeneratedHtml(result);
      setHistory([result]);
      setHistoryIndex(0);
      localStorage.setItem(STORAGE_KEY, result); 
    } catch (error) {
      if (!isResettingRef.current) {
        console.error(error);
        alert("Error generating content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setStatus(GenerationStatus.IDLE);
      }
    }
  };

  const handleSaveContent = () => {
    if (editorRef.current) {
      const cleanContent = getCleanHtml();
      setGeneratedHtml(cleanContent);
      localStorage.setItem(STORAGE_KEY, cleanContent);
      setIsEditing(false);
      pushToHistory(cleanContent);
    }
  };

  const handleRestartApp = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    // 1. Lock 
    isResettingRef.current = true;

    // 2. Clear timers
    if (historyTimeoutRef.current) {
        clearTimeout(historyTimeoutRef.current);
        historyTimeoutRef.current = null;
    }

    // 3. Reset All State immediately (Instant Reset)
    // We DO NOT clear localStorage, allowing restoration on refresh.
    setGeneratedHtml(null);
    setHistory([]);
    setHistoryIndex(-1);
    setIsEditing(false);
    setStatus(GenerationStatus.IDLE);
    setTopicInput('');
    setTextInput('');

    // 4. Reset Refs
    activeEditIdRef.current = null;
    selectionRangeRef.current = null;

    // 5. Unlock after small delay to let render cycle finish
    setTimeout(() => {
        isResettingRef.current = false;
    }, 100);
  };

  const handleExportPDF = () => {
    if (!generatedHtml) return;

    const contentToPrint = isEditing && editorRef.current 
        ? getCleanHtml() 
        : generatedHtml;

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert("Pop-up blocked! Please allow pop-ups to export PDF.");
      return;
    }

    const content = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
          <meta charset="UTF-8">
          <title>Export Notes</title>
          <link href="https://fonts.googleapis.com/css2?family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Inter:wght@400;600;800&display=swap" rel="stylesheet">
          <style>
              @page { size: A4; margin: 10mm; }
              body { font-family: 'Merriweather', serif; font-size: 10pt; line-height: 1.4; color: #000; background: white; margin: 0; padding: 10px; }
              h1 { font-family: 'Inter', sans-serif; font-size: 20pt; font-weight: 800; color: #000; border-bottom: 3px solid #000; padding-bottom: 5px; margin-top: 0; margin-bottom: 15px; page-break-after: avoid; }
              h2 { font-family: 'Inter', sans-serif; font-size: 14pt; font-weight: 700; color: #000; margin-top: 15px; margin-bottom: 8px; page-break-after: avoid; border-bottom: 1px solid #ddd; }
              h3 { font-family: 'Inter', sans-serif; font-size: 12pt; font-weight: 600; color: #000; margin-top: 10px; margin-bottom: 5px; page-break-after: avoid; }
              p { margin-bottom: 8px; text-align: justify; }
              ul, ol { margin-bottom: 10px; padding-left: 20px; }
              li { margin-bottom: 2px; }
              table { width: 100%; border-collapse: collapse; margin: 15px 0; border: 2px solid #000; page-break-inside: avoid; font-size: 9pt; }
              th { background-color: #f0f0f0; border: 1px solid #000; padding: 4px 8px; font-weight: bold; text-align: left; font-family: 'Inter', sans-serif; font-size: 9pt; }
              td { border: 1px solid #000; padding: 4px 8px; font-size: 9pt; vertical-align: top; }
              .flowchart-container { display: flex; justify-content: center; margin: 15px 0; padding: 5px; border: 1px dashed #ccc; page-break-inside: avoid; }
              svg { max-width: 100%; height: auto; }
              @media print {
                  body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                  .no-print { display: none; }
                  h1, h2, h3 { page-break-after: avoid; }
                  table, .flowchart-container { page-break-inside: avoid; }
                  p { orphans: 3; widows: 3; }
              }
          </style>
      </head>
      <body>
          ${contentToPrint}
          <script>
              window.onload = function() {
                  setTimeout(function() { window.print(); }, 800);
              }
          </script>
      </body>
      </html>
    `;

    printWindow.document.open();
    printWindow.document.write(content);
    printWindow.document.close();
  };

  // --- REWRITE HANDLERS ---

  const openSelectionRewriteModal = () => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.toString().trim().length === 0) {
      alert("Please select some text to rewrite first.");
      return;
    }
    selectionRangeRef.current = selection.getRangeAt(0);
    setRewriteType('selection');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const handleRewriteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsRewriting(true);

    try {
      const rawBefore = getCurrentHtml();
      pushToHistory(rawBefore);

      let resultHtml = "";

      if (rewriteType === 'section') {
         if (editTab === 'rewrite') {
           resultHtml = await rewriteSection(activeSectionHtml, rewriteInstruction);
         } else if (editTab === 'expand') {
           resultHtml = await expandSection(activeSectionHtml, rewriteInstruction);
         } else if (editTab === 'continue') {
           resultHtml = await generateNextContent(activeSectionHtml, rewriteInstruction);
         }
      } else {
         const selectedText = selectionRangeRef.current?.toString() || "";
         if (editTab === 'rewrite') {
             resultHtml = await rewriteContent(selectedText, rewriteInstruction);
         } else if (editTab === 'expand') {
             resultHtml = await expandSection(selectedText, rewriteInstruction);
         } else if (editTab === 'continue') {
             const nextContent = await generateNextContent(selectedText, rewriteInstruction);
             resultHtml = selectedText + " " + nextContent;
         }
      }

      // Check reset
      if (isResettingRef.current) return;

      if (!resultHtml) throw new Error("No content generated");

      // Apply to DOM
      if (rewriteType === 'section') {
         const editId = activeEditIdRef.current;
         if (!editorRef.current || !editId) throw new Error("Editor context lost.");

         const startNode = editorRef.current.querySelector(`[data-edit-id="${editId}"]`);
         if (!startNode) throw new Error("Lost position.");

         const nodesToReplace = getSectionNodes(startNode);
         const firstNode = nodesToReplace[0];
         const lastNode = nodesToReplace[nodesToReplace.length - 1];
         const parent = firstNode.parentNode;

         if (!parent) throw new Error("Parent node lost.");

         const range = document.createRange();
         range.setStartBefore(firstNode);
         const fragment = range.createContextualFragment(resultHtml);

         if (editTab === 'continue') {
            if (lastNode.nextSibling) {
               parent.insertBefore(fragment, lastNode.nextSibling);
            } else {
               parent.appendChild(fragment);
            }
            startNode.removeAttribute('data-edit-id');
         } else {
            parent.insertBefore(fragment, firstNode);
            nodesToReplace.forEach(n => n.remove());
         }

      } else {
         const range = selectionRangeRef.current;
         if (range) {
             const fragment = range.createContextualFragment(resultHtml);
             range.deleteContents();
             range.insertNode(fragment);

             const selection = window.getSelection();
             selection?.removeAllRanges();
         }
      }

      setRewriteModalOpen(false);

      if (editorRef.current) {
        const rawContent = getCurrentHtml();
        setGeneratedHtml(rawContent);
        pushToHistory(rawContent);
        saveToStorage();
      }

    } catch (error) {
      if (!isResettingRef.current) {
        console.error("Rewrite failed:", error);
        alert("Failed to update content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setIsRewriting(false);
      }
    }
  };

  // --- RENDER ---

  if (!generatedHtml && status === GenerationStatus.IDLE) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
        <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl overflow-hidden animate-in fade-in zoom-in duration-300">

          <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-8 text-white text-center">
            <BookOpen className="w-12 h-12 mx-auto mb-4 opacity-90" />
            <h1 className="text-3xl font-bold mb-2">AI Book Writer</h1>
            <p className="opacity-90">Generate structured notes, books, and study guides instantly.</p>
          </div>

          <div className="p-8">
            <div className="bg-gray-100 p-1 rounded-xl flex mb-8 relative">
              <button
                onClick={() => setMode('topic')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-semibold transition-all duration-200 ${
                  mode === 'topic' ? 'bg-white text-blue-700 shadow-md' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <Sparkles className="w-4 h-4" />
                Generate from Topic
              </button>
              <button
                onClick={() => setMode('text')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-semibold transition-all duration-200 ${
                  mode === 'text' ? 'bg-white text-blue-700 shadow-md' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <FileText className="w-4 h-4" />
                Format Existing Text
              </button>
            </div>

            <form onSubmit={handleGenerate} className="space-y-6">
              <div className="min-h-[120px]">
                {mode === 'topic' ? (
                  <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">What do you want to write about?</label>
                    <div className="relative">
                      <input 
                        type="text" 
                        value={topicInput}
                        onChange={(e) => setTopicInput(e.target.value)}
                        placeholder="e.g. History of India, Quantum Physics..."
                        className="w-full px-4 py-4 text-lg border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all bg-white text-gray-900 placeholder-gray-400"
                        autoFocus
                      />
                      <div className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none"><Sparkles className="w-5 h-5" /></div>
                    </div>
                  </div>
                ) : (
                  <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Paste your text here</label>
                    <textarea 
                      value={textInput}
                      onChange={(e) => setTextInput(e.target.value)}
                      placeholder="Paste unstructured notes..."
                      className="w-full h-64 px-4 py-4 text-base border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none resize-none transition-all bg-white text-gray-900 placeholder-gray-400"
                    />
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wide mb-1.5">Output Language</label>
                    <select 
                      value={language} 
                      onChange={(e) => setLanguage(e.target.value)}
                      className="w-full px-4 py-3 bg-white border border-gray-200 rounded-lg text-gray-900 focus:ring-2 focus:ring-blue-500 outline-none"
                    >
                      <option value="Hindi">Hindi (हिन्दी)</option>
                      <option value="English">English</option>
                      <option value="Hinglish">Hinglish</option>
                    </select>
                 </div>
                 <div className="flex items-end">
                    <Button type="submit" className="w-full py-3.5 text-base font-bold shadow-lg shadow-blue-500/30 hover:shadow-blue-500/50 transition-all transform active:scale-95">
                      {mode === 'topic' ? 'Generate Book Chapter' : 'Format & Structure Text'}
                    </Button>
                 </div>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  if (status !== GenerationStatus.IDLE) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-8"></div>
        <h2 className="text-2xl font-bold text-gray-800 animate-pulse">
          {mode === 'topic' ? 'Writing your book...' : 'Organizing your notes...'}
        </h2>
        <div className="mt-4 space-y-2 text-center text-gray-500">
           <p>Designing layout</p>
           <p>Creating flowcharts</p>
           <p>Formatting tables</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-gray-200 overflow-hidden font-sans">

      <header className="bg-white border-b border-gray-300 h-16 flex items-center justify-between px-4 lg:px-8 shadow-sm z-20 no-print">
        <div className="flex items-center gap-4">
          <Button 
            onClick={handleRestartApp} 
            variant="secondary"
            className="flex items-center gap-2 text-sm font-semibold border-gray-300 hover:bg-gray-100 hover:text-blue-600 transition-all"
          >
            <Plus className="w-4 h-4" /> New
          </Button>

          <div className="h-6 w-px bg-gray-300 hidden sm:block"></div>
          <span className="font-serif font-bold text-gray-800 hidden sm:block truncate max-w-[200px] lg:max-w-[400px]">
            {mode === 'topic' ? (topicInput || 'Untitled') : 'Formatted Notes'}
          </span>
          <span className="hidden lg:flex text-xs text-green-600 bg-green-50 px-2 py-1 rounded-full items-center gap-1 opacity-80">
            <Save className="w-3 h-3" /> Auto-saved
          </span>
        </div>

        <div className="flex items-center gap-2 sm:gap-3">
          {/* HISTORY CONTROLS */}
          <div className="flex items-center bg-gray-100 rounded-lg p-1 mr-1 sm:mr-2">
             <Button 
                variant="ghost" 
                onClick={handleUndo} 
                disabled={historyIndex <= 0}
                className={`p-1.5 h-8 w-8 rounded-md transition-all ${historyIndex <= 0 ? '!text-gray-400' : '!text-gray-900 hover:bg-white hover:shadow-sm'}`}
                title="Undo"
             >
                <Undo className="w-4 h-4" />
             </Button>
             <div className="w-px h-4 bg-gray-300 mx-1"></div>
             <Button 
                variant="ghost" 
                onClick={handleRedo} 
                disabled={historyIndex >= history.length - 1}
                className={`p-1.5 h-8 w-8 rounded-md transition-all ${historyIndex >= history.length - 1 ? '!text-gray-400' : '!text-gray-900 hover:bg-white hover:shadow-sm'}`}
                title="Redo"
             >
                <Redo className="w-4 h-4" />
             </Button>
          </div>

          {isEditing ? (
             <div className="flex items-center gap-2 animate-in fade-in duration-200">
                <Button 
                  variant="ghost" 
                  onClick={openSelectionRewriteModal} 
                  icon={<Wand2 className="w-4 h-4 text-purple-600"/>}
                  className="text-sm border border-purple-200 bg-purple-50 text-purple-700 hover:bg-purple-100 hidden sm:flex"
                >
                  <span className="hidden sm:inline">Rewrite</span>
                </Button>
                {/* Mobile Icon Only for Rewrite */}
                <Button 
                  variant="ghost" 
                  onClick={openSelectionRewriteModal} 
                  className="text-sm border border-purple-200 bg-purple-50 text-purple-700 hover:bg-purple-100 sm:hidden p-2"
                >
                  <Wand2 className="w-4 h-4" />
                </Button>

                <Button variant="primary" onClick={handleSaveContent} icon={<Check className="w-4 h-4"/>} className="bg-green-600 hover:bg-green-700 text-sm">
                  <span className="hidden sm:inline">Done</span>
                </Button>
             </div>
          ) : (
             <Button variant="secondary" onClick={() => setIsEditing(true)} icon={<PenTool className="w-4 h-4"/>} className="text-sm">
               <span className="hidden sm:inline">Edit</span>
             </Button>
          )}

          <div className="h-6 w-px bg-gray-300 mx-1 hidden sm:block"></div>

          <Button variant="primary" onClick={handleExportPDF} icon={<Printer className="w-4 h-4"/>} className="text-sm shadow-sm">
            <span className="hidden sm:inline">Print</span>
          </Button>
          <Button variant="ghost" onClick={handleRestartApp} className="text-red-500 hover:bg-red-50 p-2 sm:hidden">
            <Plus className="w-5 h-5" />
          </Button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 flex justify-center bg-gray-200/80">
        <div className="w-full max-w-[210mm] transition-all duration-300">

           <div className="editor-container a4-page shadow-2xl editor-content bg-white"
             style={{ minHeight: '297mm' }}
           >
              <div 
                className={`min-h-[250mm] outline-none ${isEditing ? 'cursor-text' : ''}`}
                contentEditable={isEditing}
                suppressContentEditableWarning={true}
                ref={editorRef}
                onInput={handleEditorInput}
                onBlur={handleEditorBlur}
                dangerouslySetInnerHTML={{ __html: generatedHtml || '' }}
              />
           </div>
           <div className="text-center mt-6 mb-12 text-gray-500 text-sm font-medium no-print">End of Document</div>
        </div>
      </main>

      {rewriteModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in duration-200">

              <div className="flex items-center justify-between mb-4">
                 <h3 className="text-lg font-bold flex items-center gap-2">
                    {rewriteType === 'section' ? <Sparkles className="w-5 h-5 text-blue-600"/> : <Wand2 className="w-5 h-5 text-purple-600"/>}
                    {rewriteType === 'section' ? 'Magic AI Editor' : 'Rewrite Selection'}
                 </h3>
                 <button onClick={() => setRewriteModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                   <ArrowLeft className="w-5 h-5 rotate-180" />
                 </button>
              </div>

              <div className="flex p-1 bg-gray-100 rounded-lg mb-4">
                  <button 
                     onClick={() => setEditTab('rewrite')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'rewrite' ? 'bg-white shadow text-purple-700' : 'text-gray-500'}`}
                  >
                      Rewrite
                  </button>
                  <button 
                     onClick={() => setEditTab('expand')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'expand' ? 'bg-white shadow text-blue-700' : 'text-gray-500'}`}
                  >
                      Expand (Deep Dive)
                  </button>
                  <button 
                     onClick={() => setEditTab('continue')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'continue' ? 'bg-white shadow text-green-700' : 'text-gray-500'}`}
                  >
                      {rewriteType === 'section' ? 'Add After' : 'Continue'}
                  </button>
              </div>

              <div className="mb-4 text-sm text-gray-500 bg-gray-50 p-3 rounded-lg border border-gray-100 max-h-32 overflow-y-auto">
                 <strong>Editing context:</strong>
                 <div className="italic mt-1 text-xs opacity-70">
                    {rewriteType === 'section' 
                       ? "Selected Heading + Sub-content."
                       : selectionRangeRef.current?.toString().substring(0, 100) + "..."
                    }
                 </div>
              </div>

              <form onSubmit={handleRewriteSubmit}>
                 <label className="block text-sm text-gray-600 mb-2">Instruction</label>
                 <input 
                   type="text" 
                   value={rewriteInstruction}
                   onChange={(e) => setRewriteInstruction(e.target.value)}
                   placeholder={
                       editTab === 'expand' ? "e.g. Explain Article 14, 15 separately with details..." :
                       editTab === 'continue' ? "e.g. Write the next 3 sub-points about..." :
                       "e.g. Fix grammar, make it shorter..."
                   }
                   className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 outline-none bg-white text-gray-900"
                   autoFocus
                 />
                 <div className="flex justify-end gap-3">
                    <Button type="button" variant="secondary" onClick={() => setRewriteModalOpen(false)} disabled={isRewriting}>
                        Cancel
                    </Button>
                    <Button 
                        type="submit" 
                        className={`text-white shadow-lg transition-colors ${
                            editTab === 'expand' ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-500/30' :
                            editTab === 'continue' ? 'bg-green-600 hover:bg-green-700 shadow-green-500/30' :
                            'bg-purple-600 hover:bg-purple-700 shadow-purple-500/30'
                        }`} 
                        isLoading={isRewriting}
                    >
                        {editTab === 'expand' ? 'Expand Content' : editTab === 'continue' ? 'Generate Next' : 'Rewrite'}
                    </Button>
                 </div>
              </form>
           </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  generateTopicContent, 
  generateFormattedNotes, 
  rewriteContent, 
  rewriteSection,
  expandSection,
  generateNextContent
} from './services/ai';
import { GenerationStatus } from './types';
import { Button } from './components/Button';
import { 
  BookOpen, 
  PenTool, 
  Printer, 
  Sparkles,
  FileText,
  Trash2,
  Wand2,
  ArrowLeft,
  Check,
  Save,
  Undo,
  Redo,
  RefreshCw,
  Plus
} from 'lucide-react';

const STORAGE_KEY = 'ai_book_writer_draft';

const App: React.FC = () => {
  // Mode State
  const [mode, setMode] = useState<'topic' | 'text'>('topic');

  // Shared State
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [language, setLanguage] = useState('Hindi'); // Default Hindi
  const [isEditing, setIsEditing] = useState(false);
  const editorRef = useRef<HTMLDivElement>(null);

  // History State for Undo/Redo
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const historyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Lock for Resetting
  const isResettingRef = useRef(false);

  // Rewrite State
  const [rewriteModalOpen, setRewriteModalOpen] = useState(false);
  const [rewriteInstruction, setRewriteInstruction] = useState('');
  const [isRewriting, setIsRewriting] = useState(false);

  // Ref for "Selection" rewrite (highlighted text)
  const selectionRangeRef = useRef<Range | null>(null);

  // Ref for "Section" rewrite (ID tracking)
  const activeEditIdRef = useRef<string | null>(null);
  const [activeSectionHtml, setActiveSectionHtml] = useState<string>('');
  const [rewriteType, setRewriteType] = useState<'selection' | 'section'>('selection');

  // Tabs for Section Editing
  const [editTab, setEditTab] = useState<'rewrite' | 'expand' | 'continue'>('rewrite');

  // Content State
  const [generatedHtml, setGeneratedHtml] = useState<string | null>(null);

  // Inputs
  const [topicInput, setTopicInput] = useState('');
  const [textInput, setTextInput] = useState('');

  // --- HISTORY MANAGEMENT ---

  const pushToHistory = useCallback((content: string) => {
    setHistory(prev => {
      // If content is same as current tip, don't push
      if (historyIndex >= 0 && prev[historyIndex] === content) {
        return prev;
      }
      // Slice history if we are in middle of stack
      const newHistory = prev.slice(0, historyIndex + 1);
      return [...newHistory, content];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      const content = history[newIndex];
      setGeneratedHtml(content);
      setHistoryIndex(newIndex);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      const content = history[newIndex];
      setGeneratedHtml(content);
      setHistoryIndex(newIndex);
    }
  };

  // --- PERSISTENCE & AUTO-SAVE ---

  // 1. Load from Storage on Mount ONLY
  useEffect(() => {
    const savedContent = localStorage.getItem(STORAGE_KEY);
    if (savedContent) {
      setGeneratedHtml(savedContent);
      setHistory([savedContent]);
      setHistoryIndex(0);
    }
  }, []);

  // 2. Helper to get RAW HTML (matches DOM exactly, includes edit buttons)
  const getCurrentHtml = useCallback(() => {
    return editorRef.current ? editorRef.current.innerHTML : (generatedHtml || '');
  }, [generatedHtml]);

  // 3. Helper to get CLEAN HTML (removes buttons/markers)
  const getCleanHtml = useCallback(() => {
    if (!editorRef.current) return generatedHtml || '';

    const clone = editorRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll('.ai-edit-trigger').forEach(b => b.remove());
    clone.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    return clone.innerHTML;
  }, [generatedHtml]);

  // 4. Save Function (Saves Clean Version)
  const saveToStorage = useCallback(() => {
    if (isResettingRef.current) return; // Don't save if resetting
    const content = getCleanHtml();
    if (content) {
      localStorage.setItem(STORAGE_KEY, content);
    }
    return content;
  }, [getCleanHtml]);

  // 5. Event Listeners
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        saveToStorage();
      }
    };

    const intervalId = setInterval(() => {
      if (isEditing) saveToStorage();
    }, 5000);

    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('pagehide', saveToStorage);
    window.addEventListener('beforeunload', saveToStorage);

    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', saveToStorage);
      window.removeEventListener('beforeunload', saveToStorage);
      clearInterval(intervalId);
    };
  }, [saveToStorage, isEditing]);

  // 6. Live Input Handler
  const handleEditorInput = () => {
    if (isResettingRef.current) return;

    if (historyTimeoutRef.current) {
      clearTimeout(historyTimeoutRef.current);
    }

    historyTimeoutRef.current = setTimeout(() => {
       if (isResettingRef.current) return;
       const rawContent = getCurrentHtml(); 
       setGeneratedHtml(rawContent); 
       pushToHistory(rawContent);
       saveToStorage();
    }, 800);
  };

  const handleEditorBlur = () => {
      if (isResettingRef.current) return;
      const rawContent = getCurrentHtml();
      setGeneratedHtml(rawContent);
  };

  // --- HELPER: Identify Section Nodes ---
  const getSectionNodes = (startNode: Element): Element[] => {
    const nodes: Element[] = [startNode];
    const tagName = startNode.tagName;

    const getLevel = (tag: string) => {
      const t = tag.toUpperCase();
      if (t === 'H1') return 1;
      if (t === 'H2') return 2;
      if (t === 'H3') return 3;
      if (t === 'H4') return 4;
      return 10; // Regular text
    };

    const currentLevel = getLevel(tagName);

    if (currentLevel <= 4) {
      let nextSibling = startNode.nextElementSibling;
      while (nextSibling) {
        const nextTag = nextSibling.tagName;
        const nextLevel = getLevel(nextTag);
        if (nextLevel <= currentLevel) break;
        nodes.push(nextSibling);
        nextSibling = nextSibling.nextElementSibling;
      }
    } 
    return nodes;
  };

  // --- SMART EDIT BUTTON LOGIC ---
  useEffect(() => {
    if (!editorRef.current) return;

    if (isEditing) {
      const elements = editorRef.current.querySelectorAll('h1, h2, h3, h4, li');
      elements.forEach((el) => {
        if (el.querySelector('.ai-edit-trigger')) return;

        const btn = document.createElement('span');
        btn.contentEditable = "false";
        btn.className = "ai-edit-trigger no-print";
        btn.innerHTML = "✨";
        btn.title = "Rewrite/Expand this section";

        if (el.tagName === 'LI') {
           el.insertBefore(btn, el.firstChild);
        } else {
           el.appendChild(btn);
        }
      });
    } else {
      const buttons = editorRef.current.querySelectorAll('.ai-edit-trigger');
      buttons.forEach(btn => btn.remove());
    }
  }, [isEditing, generatedHtml]);

  useEffect(() => {
    const handleEditorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.classList.contains('ai-edit-trigger')) {
        e.preventDefault();
        e.stopPropagation();

        const parentEl = target.parentElement;
        if (parentEl) {
          handleSectionEdit(parentEl);
        }
      }
    };

    const editor = editorRef.current;
    if (editor) {
      editor.addEventListener('click', handleEditorClick);
    }
    return () => {
      if (editor) editor.removeEventListener('click', handleEditorClick);
    };
  }, [isEditing]);

  const handleSectionEdit = (startNode: Element) => {
    if (!editorRef.current) return;

    const currentRaw = getCurrentHtml();
    pushToHistory(currentRaw);
    setGeneratedHtml(currentRaw);

    const editId = `edit-${Date.now()}`;
    editorRef.current.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    startNode.setAttribute('data-edit-id', editId);
    activeEditIdRef.current = editId;

    const nodes = getSectionNodes(startNode);

    const tempDiv = document.createElement('div');
    nodes.forEach(node => {
        const clone = node.cloneNode(true) as Element;
        const trigger = clone.querySelector('.ai-edit-trigger');
        if(trigger) trigger.remove();
        clone.removeAttribute('data-edit-id'); 
        tempDiv.appendChild(clone);
    });

    setActiveSectionHtml(tempDiv.innerHTML);
    setGeneratedHtml(editorRef.current.innerHTML); // Sync state

    setRewriteType('section');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  // --- STANDARD HANDLERS ---

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'topic' && !topicInput.trim()) return;
    if (mode === 'text' && !textInput.trim()) return;

    setStatus(GenerationStatus.GENERATING_CHAPTER);

    try {
      let result = "";
      if (mode === 'topic') {
        result = await generateTopicContent(topicInput, language);
      } else {
        result = await generateFormattedNotes(textInput, language);
      }

      // Check if user reset app while generating
      if (isResettingRef.current) return;

      setGeneratedHtml(result);
      setHistory([result]);
      setHistoryIndex(0);
      localStorage.setItem(STORAGE_KEY, result); 
    } catch (error) {
      if (!isResettingRef.current) {
        console.error(error);
        alert("Error generating content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setStatus(GenerationStatus.IDLE);
      }
    }
  };

  const handleSaveContent = () => {
    if (editorRef.current) {
      const cleanContent = getCleanHtml();
      setGeneratedHtml(cleanContent);
      localStorage.setItem(STORAGE_KEY, cleanContent);
      setIsEditing(false);
      pushToHistory(cleanContent);
    }
  };

  const handleRestartApp = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    // 1. Lock 
    isResettingRef.current = true;

    // 2. Clear timers
    if (historyTimeoutRef.current) {
        clearTimeout(historyTimeoutRef.current);
        historyTimeoutRef.current = null;
    }

    // 3. Reset All State immediately (Instant Reset)
    // We DO NOT clear localStorage, allowing restoration on refresh.
    setGeneratedHtml(null);
    setHistory([]);
    setHistoryIndex(-1);
    setIsEditing(false);
    setStatus(GenerationStatus.IDLE);
    setTopicInput('');
    setTextInput('');

    // 4. Reset Refs
    activeEditIdRef.current = null;
    selectionRangeRef.current = null;

    // 5. Unlock after small delay to let render cycle finish
    setTimeout(() => {
        isResettingRef.current = false;
    }, 100);
  };

  const handleExportPDF = () => {
    if (!generatedHtml) return;

    const contentToPrint = isEditing && editorRef.current 
        ? getCleanHtml() 
        : generatedHtml;

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert("Pop-up blocked! Please allow pop-ups to export PDF.");
      return;
    }

    const content = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
          <meta charset="UTF-8">
          <title>Export Notes</title>
          <link href="https://fonts.googleapis.com/css2?family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Inter:wght@400;600;800&display=swap" rel="stylesheet">
          <style>
              @page { size: A4; margin: 5mm; }
              body { font-family: 'Merriweather', serif; font-size: 10pt; line-height: 1.4; color: #000; background: white; margin: 0; padding: 0; }
              .content-wrapper { padding: 5px; } 
              h1 { font-family: 'Inter', sans-serif; font-size: 20pt; font-weight: 800; color: #000; border-bottom: 3px solid #000; padding-bottom: 5px; margin-top: 0; margin-bottom: 15px; page-break-after: avoid; }
              h2 { font-family: 'Inter', sans-serif; font-size: 14pt; font-weight: 700; color: #000; margin-top: 15px; margin-bottom: 8px; page-break-after: avoid; border-bottom: 1px solid #ddd; }
              h3 { font-family: 'Inter', sans-serif; font-size: 12pt; font-weight: 600; color: #000; margin-top: 10px; margin-bottom: 5px; page-break-after: avoid; }
              p { margin-bottom: 8px; text-align: justify; }
              ul, ol { margin-bottom: 10px; padding-left: 20px; }
              li { margin-bottom: 2px; }
              table { width: 100%; border-collapse: collapse; margin: 15px 0; border: 2px solid #000; page-break-inside: avoid; font-size: 9pt; }
              th { background-color: #f0f0f0; border: 1px solid #000; padding: 4px 8px; font-weight: bold; text-align: left; font-family: 'Inter', sans-serif; font-size: 9pt; }
              td { border: 1px solid #000; padding: 4px 8px; font-size: 9pt; vertical-align: top; }
              .flowchart-container { display: flex; justify-content: center; margin: 15px 0; padding: 5px; border: 1px dashed #ccc; page-break-inside: avoid; }
              svg { max-width: 100%; height: auto; }
              @media print {
                  body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                  .no-print { display: none; }
                  h1, h2, h3 { page-break-after: avoid; }
                  table, .flowchart-container { page-break-inside: avoid; }
                  p { orphans: 3; widows: 3; }
              }
          </style>
      </head>
      <body>
          <div class="content-wrapper">
            ${contentToPrint}
          </div>
          <script>
              window.onload = function() {
                  setTimeout(function() { window.print(); }, 800);
              }
          </script>
      </body>
      </html>
    `;

    printWindow.document.open();
    printWindow.document.write(content);
    printWindow.document.close();
  };

  // --- REWRITE HANDLERS ---

  const openSelectionRewriteModal = () => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.toString().trim().length === 0) {
      alert("Please select some text to rewrite first.");
      return;
    }
    selectionRangeRef.current = selection.getRangeAt(0);
    setRewriteType('selection');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const handleRewriteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsRewriting(true);

    try {
      const rawBefore = getCurrentHtml();
      pushToHistory(rawBefore);

      let resultHtml = "";

      if (rewriteType === 'section') {
         if (editTab === 'rewrite') {
           resultHtml = await rewriteSection(activeSectionHtml, rewriteInstruction);
         } else if (editTab === 'expand') {
           resultHtml = await expandSection(activeSectionHtml, rewriteInstruction);
         } else if (editTab === 'continue') {
           resultHtml = await generateNextContent(activeSectionHtml, rewriteInstruction);
         }
      } else {
         const selectedText = selectionRangeRef.current?.toString() || "";
         if (editTab === 'rewrite') {
             resultHtml = await rewriteContent(selectedText, rewriteInstruction);
         } else if (editTab === 'expand') {
             resultHtml = await expandSection(selectedText, rewriteInstruction);
         } else if (editTab === 'continue') {
             const nextContent = await generateNextContent(selectedText, rewriteInstruction);
             resultHtml = selectedText + " " + nextContent;
         }
      }

      // Check reset
      if (isResettingRef.current) return;

      if (!resultHtml) throw new Error("No content generated");

      // Apply to DOM
      if (rewriteType === 'section') {
         const editId = activeEditIdRef.current;
         if (!editorRef.current || !editId) throw new Error("Editor context lost.");

         const startNode = editorRef.current.querySelector(`[data-edit-id="${editId}"]`);
         if (!startNode) throw new Error("Lost position.");

         const nodesToReplace = getSectionNodes(startNode);
         const firstNode = nodesToReplace[0];
         const lastNode = nodesToReplace[nodesToReplace.length - 1];
         const parent = firstNode.parentNode;

         if (!parent) throw new Error("Parent node lost.");

         const range = document.createRange();
         range.setStartBefore(firstNode);
         const fragment = range.createContextualFragment(resultHtml);

         if (editTab === 'continue') {
            if (lastNode.nextSibling) {
               parent.insertBefore(fragment, lastNode.nextSibling);
            } else {
               parent.appendChild(fragment);
            }
            startNode.removeAttribute('data-edit-id');
         } else {
            parent.insertBefore(fragment, firstNode);
            nodesToReplace.forEach(n => n.remove());
         }

      } else {
         const range = selectionRangeRef.current;
         if (range) {
             const fragment = range.createContextualFragment(resultHtml);
             range.deleteContents();
             range.insertNode(fragment);

             const selection = window.getSelection();
             selection?.removeAllRanges();
         }
      }

      setRewriteModalOpen(false);

      if (editorRef.current) {
        const rawContent = getCurrentHtml();
        setGeneratedHtml(rawContent);
        pushToHistory(rawContent);
        saveToStorage();
      }

    } catch (error) {
      if (!isResettingRef.current) {
        console.error("Rewrite failed:", error);
        alert("Failed to update content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setIsRewriting(false);
      }
    }
  };

  // --- RENDER ---

  if (!generatedHtml && status === GenerationStatus.IDLE) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
        <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl overflow-hidden animate-in fade-in zoom-in duration-300">

          <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-8 text-white text-center">
            <BookOpen className="w-12 h-12 mx-auto mb-4 opacity-90" />
            <h1 className="text-3xl font-bold mb-2">AI Book Writer</h1>
            <p className="opacity-90">Generate structured notes, books, and study guides instantly.</p>
          </div>

          <div className="p-8">
            <div className="bg-gray-100 p-1 rounded-xl flex mb-8 relative">
              <button
                onClick={() => setMode('topic')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-semibold transition-all duration-200 ${
                  mode === 'topic' ? 'bg-white text-blue-700 shadow-md' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <Sparkles className="w-4 h-4" />
                Generate from Topic
              </button>
              <button
                onClick={() => setMode('text')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-semibold transition-all duration-200 ${
                  mode === 'text' ? 'bg-white text-blue-700 shadow-md' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <FileText className="w-4 h-4" />
                Format Existing Text
              </button>
            </div>

            <form onSubmit={handleGenerate} className="space-y-6">
              <div className="min-h-[120px]">
                {mode === 'topic' ? (
                  <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">What do you want to write about?</label>
                    <div className="relative">
                      <input 
                        type="text" 
                        value={topicInput}
                        onChange={(e) => setTopicInput(e.target.value)}
                        placeholder="e.g. History of India, Quantum Physics..."
                        className="w-full px-4 py-4 text-lg border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all bg-white text-gray-900 placeholder-gray-400"
                        autoFocus
                      />
                      <div className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none"><Sparkles className="w-5 h-5" /></div>
                    </div>
                  </div>
                ) : (
                  <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Paste your text here</label>
                    <textarea 
                      value={textInput}
                      onChange={(e) => setTextInput(e.target.value)}
                      placeholder="Paste unstructured notes..."
                      className="w-full h-64 px-4 py-4 text-base border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none resize-none transition-all bg-white text-gray-900 placeholder-gray-400"
                    />
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wide mb-1.5">Output Language</label>
                    <select 
                      value={language} 
                      onChange={(e) => setLanguage(e.target.value)}
                      className="w-full px-4 py-3 bg-white border border-gray-200 rounded-lg text-gray-900 focus:ring-2 focus:ring-blue-500 outline-none"
                    >
                      <option value="Hindi">Hindi (हिन्दी)</option>
                      <option value="English">English</option>
                      <option value="Hinglish">Hinglish</option>
                    </select>
                 </div>
                 <div className="flex items-end">
                    <Button type="submit" className="w-full py-3.5 text-base font-bold shadow-lg shadow-blue-500/30 hover:shadow-blue-500/50 transition-all transform active:scale-95">
                      {mode === 'topic' ? 'Generate Book Chapter' : 'Format & Structure Text'}
                    </Button>
                 </div>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  if (status !== GenerationStatus.IDLE) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-8"></div>
        <h2 className="text-2xl font-bold text-gray-800 animate-pulse">
          {mode === 'topic' ? 'Writing your book...' : 'Organizing your notes...'}
        </h2>
        <div className="mt-4 space-y-2 text-center text-gray-500">
           <p>Designing layout</p>
           <p>Creating flowcharts</p>
           <p>Formatting tables</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-gray-200 overflow-hidden font-sans">

      <header className="bg-white border-b border-gray-300 h-16 flex items-center justify-between px-4 lg:px-8 shadow-sm z-20 no-print">
        <div className="flex items-center gap-4">
          <Button 
            onClick={handleRestartApp} 
            variant="secondary"
            className="flex items-center gap-2 text-sm font-semibold border-gray-300 hover:bg-gray-100 hover:text-blue-600 transition-all"
          >
            <Plus className="w-4 h-4" /> New
          </Button>

          <div className="h-6 w-px bg-gray-300 hidden sm:block"></div>
          <span className="font-serif font-bold text-gray-800 hidden sm:block truncate max-w-[200px] lg:max-w-[400px]">
            {mode === 'topic' ? (topicInput || 'Untitled') : 'Formatted Notes'}
          </span>
          <span className="hidden lg:flex text-xs text-green-600 bg-green-50 px-2 py-1 rounded-full items-center gap-1 opacity-80">
            <Save className="w-3 h-3" /> Auto-saved
          </span>
        </div>

        <div className="flex items-center gap-2 sm:gap-3">
          {/* HISTORY CONTROLS */}
          <div className="flex items-center bg-gray-100 rounded-lg p-1 mr-1 sm:mr-2">
             <Button 
                variant="ghost" 
                onClick={handleUndo} 
                disabled={historyIndex <= 0}
                className={`p-1.5 h-8 w-8 rounded-md transition-all ${historyIndex <= 0 ? '!text-gray-400' : '!text-gray-900 hover:bg-white hover:shadow-sm'}`}
                title="Undo"
             >
                <Undo className="w-4 h-4" />
             </Button>
             <div className="w-px h-4 bg-gray-300 mx-1"></div>
             <Button 
                variant="ghost" 
                onClick={handleRedo} 
                disabled={historyIndex >= history.length - 1}
                className={`p-1.5 h-8 w-8 rounded-md transition-all ${historyIndex >= history.length - 1 ? '!text-gray-400' : '!text-gray-900 hover:bg-white hover:shadow-sm'}`}
                title="Redo"
             >
                <Redo className="w-4 h-4" />
             </Button>
          </div>

          {isEditing ? (
             <div className="flex items-center gap-2 animate-in fade-in duration-200">
                <Button 
                  variant="ghost" 
                  onClick={openSelectionRewriteModal} 
                  icon={<Wand2 className="w-4 h-4 text-purple-600"/>}
                  className="text-sm border border-purple-200 bg-purple-50 text-purple-700 hover:bg-purple-100 hidden sm:flex"
                >
                  <span className="hidden sm:inline">Rewrite</span>
                </Button>
                {/* Mobile Icon Only for Rewrite */}
                <Button 
                  variant="ghost" 
                  onClick={openSelectionRewriteModal} 
                  className="text-sm border border-purple-200 bg-purple-50 text-purple-700 hover:bg-purple-100 sm:hidden p-2"
                >
                  <Wand2 className="w-4 h-4" />
                </Button>

                <Button variant="primary" onClick={handleSaveContent} icon={<Check className="w-4 h-4"/>} className="bg-green-600 hover:bg-green-700 text-sm">
                  <span className="hidden sm:inline">Done</span>
                </Button>
             </div>
          ) : (
             <Button variant="secondary" onClick={() => setIsEditing(true)} icon={<PenTool className="w-4 h-4"/>} className="text-sm">
               <span className="hidden sm:inline">Edit</span>
             </Button>
          )}

          <div className="h-6 w-px bg-gray-300 mx-1 hidden sm:block"></div>

          <Button variant="primary" onClick={handleExportPDF} icon={<Printer className="w-4 h-4"/>} className="text-sm shadow-sm">
            <span className="hidden sm:inline">Print</span>
          </Button>
          <Button variant="ghost" onClick={handleRestartApp} className="text-red-500 hover:bg-red-50 p-2 sm:hidden">
            <Plus className="w-5 h-5" />
          </Button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 flex justify-center bg-gray-200/80">
        <div className="w-full max-w-[210mm] transition-all duration-300">

           <div className="editor-container a4-page shadow-2xl editor-content bg-white"
             style={{ minHeight: '297mm' }}
           >
              <div 
                className={`min-h-[250mm] outline-none ${isEditing ? 'cursor-text' : ''}`}
                contentEditable={isEditing}
                suppressContentEditableWarning={true}
                ref={editorRef}
                onInput={handleEditorInput}
                onBlur={handleEditorBlur}
                dangerouslySetInnerHTML={{ __html: generatedHtml || '' }}
              />
           </div>
           <div className="text-center mt-6 mb-12 text-gray-500 text-sm font-medium no-print">End of Document</div>
        </div>
      </main>

      {rewriteModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in duration-200">

              <div className="flex items-center justify-between mb-4">
                 <h3 className="text-lg font-bold flex items-center gap-2">
                    {rewriteType === 'section' ? <Sparkles className="w-5 h-5 text-blue-600"/> : <Wand2 className="w-5 h-5 text-purple-600"/>}
                    {rewriteType === 'section' ? 'Magic AI Editor' : 'Rewrite Selection'}
                 </h3>
                 <button onClick={() => setRewriteModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                   <ArrowLeft className="w-5 h-5 rotate-180" />
                 </button>
              </div>

              <div className="flex p-1 bg-gray-100 rounded-lg mb-4">
                  <button 
                     onClick={() => setEditTab('rewrite')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'rewrite' ? 'bg-white shadow text-purple-700' : 'text-gray-500'}`}
                  >
                      Rewrite
                  </button>
                  <button 
                     onClick={() => setEditTab('expand')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'expand' ? 'bg-white shadow text-blue-700' : 'text-gray-500'}`}
                  >
                      Expand (Deep Dive)
                  </button>
                  <button 
                     onClick={() => setEditTab('continue')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'continue' ? 'bg-white shadow text-green-700' : 'text-gray-500'}`}
                  >
                      {rewriteType === 'section' ? 'Add After' : 'Continue'}
                  </button>
              </div>

              <div className="mb-4 text-sm text-gray-500 bg-gray-50 p-3 rounded-lg border border-gray-100 max-h-32 overflow-y-auto">
                 <strong>Editing context:</strong>
                 <div className="italic mt-1 text-xs opacity-70">
                    {rewriteType === 'section' 
                       ? "Selected Heading + Sub-content."
                       : selectionRangeRef.current?.toString().substring(0, 100) + "..."
                    }
                 </div>
              </div>

              <form onSubmit={handleRewriteSubmit}>
                 <label className="block text-sm text-gray-600 mb-2">Instruction</label>
                 <input 
                   type="text" 
                   value={rewriteInstruction}
                   onChange={(e) => setRewriteInstruction(e.target.value)}
                   placeholder={
                       editTab === 'expand' ? "e.g. Explain Article 14, 15 separately with details..." :
                       editTab === 'continue' ? "e.g. Write the next 3 sub-points about..." :
                       "e.g. Fix grammar, make it shorter..."
                   }
                   className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 outline-none bg-white text-gray-900"
                   autoFocus
                 />
                 <div className="flex justify-end gap-3">
                    <Button type="button" variant="secondary" onClick={() => setRewriteModalOpen(false)} disabled={isRewriting}>
                        Cancel
                    </Button>
                    <Button 
                        type="submit" 
                        className={`text-white shadow-lg transition-colors ${
                            editTab === 'expand' ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-500/30' :
                            editTab === 'continue' ? 'bg-green-600 hover:bg-green-700 shadow-green-500/30' :
                            'bg-purple-600 hover:bg-purple-700 shadow-purple-500/30'
                        }`} 
                        isLoading={isRewriting}
                    >
                        {editTab === 'expand' ? 'Expand Content' : editTab === 'continue' ? 'Generate Next' : 'Rewrite'}
                    </Button>
                 </div>
              </form>
           </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  generateTopicContent, 
  generateFormattedNotes, 
  rewriteContent, 
  rewriteSection,
  expandSection,
  generateNextContent
} from './services/ai';
import { GenerationStatus } from './types';
import { Button } from './components/Button';
import { 
  BookOpen, 
  PenTool, 
  Printer, 
  Sparkles,
  FileText,
  Trash2,
  Wand2,
  ArrowLeft,
  Check,
  Save,
  Undo,
  Redo,
  RefreshCw,
  Plus
} from 'lucide-react';

const STORAGE_KEY = 'ai_book_writer_draft';

const App: React.FC = () => {
  // Mode State
  const [mode, setMode] = useState<'topic' | 'text'>('topic');

  // Shared State
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [language, setLanguage] = useState('Hindi'); // Default Hindi
  const [isEditing, setIsEditing] = useState(false);
  const editorRef = useRef<HTMLDivElement>(null);

  // History State for Undo/Redo
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const historyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Lock for Resetting
  const isResettingRef = useRef(false);

  // Rewrite State
  const [rewriteModalOpen, setRewriteModalOpen] = useState(false);
  const [rewriteInstruction, setRewriteInstruction] = useState('');
  const [isRewriting, setIsRewriting] = useState(false);

  // Ref for "Selection" rewrite (highlighted text)
  const selectionRangeRef = useRef<Range | null>(null);

  // Ref for "Section" rewrite (ID tracking)
  const activeEditIdRef = useRef<string | null>(null);
  const [activeSectionHtml, setActiveSectionHtml] = useState<string>('');
  const [rewriteType, setRewriteType] = useState<'selection' | 'section'>('selection');

  // Tabs for Section Editing
  const [editTab, setEditTab] = useState<'rewrite' | 'expand' | 'continue'>('rewrite');

  // Content State
  const [generatedHtml, setGeneratedHtml] = useState<string | null>(null);

  // Inputs
  const [topicInput, setTopicInput] = useState('');
  const [textInput, setTextInput] = useState('');

  // --- HISTORY MANAGEMENT ---

  const pushToHistory = useCallback((content: string) => {
    setHistory(prev => {
      // If content is same as current tip, don't push
      if (historyIndex >= 0 && prev[historyIndex] === content) {
        return prev;
      }
      // Slice history if we are in middle of stack
      const newHistory = prev.slice(0, historyIndex + 1);
      return [...newHistory, content];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      const content = history[newIndex];
      setGeneratedHtml(content);
      setHistoryIndex(newIndex);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      const content = history[newIndex];
      setGeneratedHtml(content);
      setHistoryIndex(newIndex);
    }
  };

  // --- PERSISTENCE & AUTO-SAVE ---

  // 1. Load from Storage on Mount ONLY
  useEffect(() => {
    const savedContent = localStorage.getItem(STORAGE_KEY);
    if (savedContent) {
      setGeneratedHtml(savedContent);
      setHistory([savedContent]);
      setHistoryIndex(0);
    }
  }, []);

  // 2. Helper to get RAW HTML (matches DOM exactly, includes edit buttons)
  const getCurrentHtml = useCallback(() => {
    return editorRef.current ? editorRef.current.innerHTML : (generatedHtml || '');
  }, [generatedHtml]);

  // 3. Helper to get CLEAN HTML (removes buttons/markers)
  const getCleanHtml = useCallback(() => {
    if (!editorRef.current) return generatedHtml || '';

    const clone = editorRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll('.ai-edit-trigger').forEach(b => b.remove());
    clone.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    return clone.innerHTML;
  }, [generatedHtml]);

  // 4. Save Function (Saves Clean Version)
  const saveToStorage = useCallback(() => {
    if (isResettingRef.current) return; // Don't save if resetting
    const content = getCleanHtml();
    if (content) {
      localStorage.setItem(STORAGE_KEY, content);
    }
    return content;
  }, [getCleanHtml]);

  // 5. Event Listeners
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') {
        saveToStorage();
      }
    };

    const intervalId = setInterval(() => {
      if (isEditing) saveToStorage();
    }, 5000);

    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('pagehide', saveToStorage);
    window.addEventListener('beforeunload', saveToStorage);

    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', saveToStorage);
      window.removeEventListener('beforeunload', saveToStorage);
      clearInterval(intervalId);
    };
  }, [saveToStorage, isEditing]);

  // 6. Live Input Handler
  const handleEditorInput = () => {
    if (isResettingRef.current) return;

    if (historyTimeoutRef.current) {
      clearTimeout(historyTimeoutRef.current);
    }

    historyTimeoutRef.current = setTimeout(() => {
       if (isResettingRef.current) return;
       const rawContent = getCurrentHtml(); 
       setGeneratedHtml(rawContent); 
       pushToHistory(rawContent);
       saveToStorage();
    }, 800);
  };

  const handleEditorBlur = () => {
      if (isResettingRef.current) return;
      const rawContent = getCurrentHtml();
      setGeneratedHtml(rawContent);
  };

  // --- HELPER: Identify Section Nodes ---
  const getSectionNodes = (startNode: Element): Element[] => {
    const nodes: Element[] = [startNode];
    const tagName = startNode.tagName;

    const getLevel = (tag: string) => {
      const t = tag.toUpperCase();
      if (t === 'H1') return 1;
      if (t === 'H2') return 2;
      if (t === 'H3') return 3;
      if (t === 'H4') return 4;
      return 10; // Regular text
    };

    const currentLevel = getLevel(tagName);

    if (currentLevel <= 4) {
      let nextSibling = startNode.nextElementSibling;
      while (nextSibling) {
        const nextTag = nextSibling.tagName;
        const nextLevel = getLevel(nextTag);
        if (nextLevel <= currentLevel) break;
        nodes.push(nextSibling);
        nextSibling = nextSibling.nextElementSibling;
      }
    } 
    return nodes;
  };

  // --- SMART EDIT BUTTON LOGIC ---
  useEffect(() => {
    if (!editorRef.current) return;

    if (isEditing) {
      const elements = editorRef.current.querySelectorAll('h1, h2, h3, h4, li');
      elements.forEach((el) => {
        if (el.querySelector('.ai-edit-trigger')) return;

        const btn = document.createElement('span');
        btn.contentEditable = "false";
        btn.className = "ai-edit-trigger no-print";
        btn.innerHTML = "✨";
        btn.title = "Rewrite/Expand this section";

        if (el.tagName === 'LI') {
           el.insertBefore(btn, el.firstChild);
        } else {
           el.appendChild(btn);
        }
      });
    } else {
      const buttons = editorRef.current.querySelectorAll('.ai-edit-trigger');
      buttons.forEach(btn => btn.remove());
    }
  }, [isEditing, generatedHtml]);

  useEffect(() => {
    const handleEditorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.classList.contains('ai-edit-trigger')) {
        e.preventDefault();
        e.stopPropagation();

        const parentEl = target.parentElement;
        if (parentEl) {
          handleSectionEdit(parentEl);
        }
      }
    };

    const editor = editorRef.current;
    if (editor) {
      editor.addEventListener('click', handleEditorClick);
    }
    return () => {
      if (editor) editor.removeEventListener('click', handleEditorClick);
    };
  }, [isEditing]);

  const handleSectionEdit = (startNode: Element) => {
    if (!editorRef.current) return;

    const currentRaw = getCurrentHtml();
    pushToHistory(currentRaw);
    setGeneratedHtml(currentRaw);

    const editId = `edit-${Date.now()}`;
    editorRef.current.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    startNode.setAttribute('data-edit-id', editId);
    activeEditIdRef.current = editId;

    const nodes = getSectionNodes(startNode);

    const tempDiv = document.createElement('div');
    nodes.forEach(node => {
        const clone = node.cloneNode(true) as Element;
        const trigger = clone.querySelector('.ai-edit-trigger');
        if(trigger) trigger.remove();
        clone.removeAttribute('data-edit-id'); 
        tempDiv.appendChild(clone);
    });

    setActiveSectionHtml(tempDiv.innerHTML);
    setGeneratedHtml(editorRef.current.innerHTML); // Sync state

    setRewriteType('section');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  // --- STANDARD HANDLERS ---

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (mode === 'topic' && !topicInput.trim()) return;
    if (mode === 'text' && !textInput.trim()) return;

    setStatus(GenerationStatus.GENERATING_CHAPTER);

    try {
      let result = "";
      if (mode === 'topic') {
        result = await generateTopicContent(topicInput, language);
      } else {
        result = await generateFormattedNotes(textInput, language);
      }

      // Check if user reset app while generating
      if (isResettingRef.current) return;

      setGeneratedHtml(result);
      setHistory([result]);
      setHistoryIndex(0);
      localStorage.setItem(STORAGE_KEY, result); 
    } catch (error) {
      if (!isResettingRef.current) {
        console.error(error);
        alert("Error generating content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setStatus(GenerationStatus.IDLE);
      }
    }
  };

  const handleSaveContent = () => {
    if (editorRef.current) {
      const cleanContent = getCleanHtml();
      setGeneratedHtml(cleanContent);
      localStorage.setItem(STORAGE_KEY, cleanContent);
      setIsEditing(false);
      pushToHistory(cleanContent);
    }
  };

  const handleRestartApp = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    // 1. Lock 
    isResettingRef.current = true;

    // 2. Clear timers
    if (historyTimeoutRef.current) {
        clearTimeout(historyTimeoutRef.current);
        historyTimeoutRef.current = null;
    }

    // 3. Reset All State immediately (Instant Reset)
    // We DO NOT clear localStorage, allowing restoration on refresh.
    setGeneratedHtml(null);
    setHistory([]);
    setHistoryIndex(-1);
    setIsEditing(false);
    setStatus(GenerationStatus.IDLE);
    setTopicInput('');
    setTextInput('');

    // 4. Reset Refs
    activeEditIdRef.current = null;
    selectionRangeRef.current = null;

    // 5. Unlock after small delay to let render cycle finish
    setTimeout(() => {
        isResettingRef.current = false;
    }, 100);
  };

  const handleExportPDF = () => {
    if (!generatedHtml) return;

    const contentToPrint = isEditing && editorRef.current 
        ? getCleanHtml() 
        : generatedHtml;

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      alert("Pop-up blocked! Please allow pop-ups to export PDF.");
      return;
    }

    const content = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
          <meta charset="UTF-8">
          <title>Export Notes</title>
          <link href="https://fonts.googleapis.com/css2?family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Inter:wght@400;600;800&display=swap" rel="stylesheet">
          <style>
              @page { size: A4; margin: 5mm; }
              body { font-family: 'Merriweather', serif; font-size: 10pt; line-height: 1.4; color: #000; background: white; margin: 0; padding: 0; }
              /* REMOVED .content-wrapper PADDING TO MATCH SCREEN */
              h1 { font-family: 'Inter', sans-serif; font-size: 20pt; font-weight: 800; color: #000; border-bottom: 3px solid #000; padding-bottom: 5px; margin-top: 0; margin-bottom: 15px; page-break-after: avoid; }
              h2 { font-family: 'Inter', sans-serif; font-size: 14pt; font-weight: 700; color: #000; margin-top: 15px; margin-bottom: 8px; page-break-after: avoid; border-bottom: 1px solid #ddd; }
              h3 { font-family: 'Inter', sans-serif; font-size: 12pt; font-weight: 600; color: #000; margin-top: 10px; margin-bottom: 5px; page-break-after: avoid; }
              p { margin-bottom: 8px; text-align: justify; }
              ul, ol { margin-bottom: 10px; padding-left: 20px; }
              li { margin-bottom: 2px; }
              table { width: 100%; border-collapse: collapse; margin: 15px 0; border: 2px solid #000; page-break-inside: avoid; font-size: 9pt; }
              th { background-color: #f0f0f0; border: 1px solid #000; padding: 4px 8px; font-weight: bold; text-align: left; font-family: 'Inter', sans-serif; font-size: 9pt; }
              td { border: 1px solid #000; padding: 4px 8px; font-size: 9pt; vertical-align: top; }
              .flowchart-container { display: flex; justify-content: center; margin: 15px 0; padding: 5px; border: 1px dashed #ccc; page-break-inside: avoid; }
              svg { max-width: 100%; height: auto; }
              @media print {
                  body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                  .no-print { display: none; }
                  h1, h2, h3 { page-break-after: avoid; }
                  table, .flowchart-container { page-break-inside: avoid; }
                  p { orphans: 3; widows: 3; }
              }
          </style>
      </head>
      <body>
          ${contentToPrint}
          <script>
              window.onload = function() {
                  setTimeout(function() { window.print(); }, 800);
              }
          </script>
      </body>
      </html>
    `;

    printWindow.document.open();
    printWindow.document.write(content);
    printWindow.document.close();
  };

  // --- REWRITE HANDLERS ---

  const openSelectionRewriteModal = () => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.toString().trim().length === 0) {
      alert("Please select some text to rewrite first.");
      return;
    }
    selectionRangeRef.current = selection.getRangeAt(0);
    setRewriteType('selection');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const handleRewriteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsRewriting(true);

    try {
      const rawBefore = getCurrentHtml();
      pushToHistory(rawBefore);

      let resultHtml = "";

      if (rewriteType === 'section') {
         if (editTab === 'rewrite') {
           resultHtml = await rewriteSection(activeSectionHtml, rewriteInstruction);
         } else if (editTab === 'expand') {
           resultHtml = await expandSection(activeSectionHtml, rewriteInstruction);
         } else if (editTab === 'continue') {
           resultHtml = await generateNextContent(activeSectionHtml, rewriteInstruction);
         }
      } else {
         const selectedText = selectionRangeRef.current?.toString() || "";
         if (editTab === 'rewrite') {
             resultHtml = await rewriteContent(selectedText, rewriteInstruction);
         } else if (editTab === 'expand') {
             resultHtml = await expandSection(selectedText, rewriteInstruction);
         } else if (editTab === 'continue') {
             const nextContent = await generateNextContent(selectedText, rewriteInstruction);
             resultHtml = selectedText + " " + nextContent;
         }
      }

      // Check reset
      if (isResettingRef.current) return;

      if (!resultHtml) throw new Error("No content generated");

      // Apply to DOM
      if (rewriteType === 'section') {
         const editId = activeEditIdRef.current;
         if (!editorRef.current || !editId) throw new Error("Editor context lost.");

         const startNode = editorRef.current.querySelector(`[data-edit-id="${editId}"]`);
         if (!startNode) throw new Error("Lost position.");

         const nodesToReplace = getSectionNodes(startNode);
         const firstNode = nodesToReplace[0];
         const lastNode = nodesToReplace[nodesToReplace.length - 1];
         const parent = firstNode.parentNode;

         if (!parent) throw new Error("Parent node lost.");

         const range = document.createRange();
         range.setStartBefore(firstNode);
         const fragment = range.createContextualFragment(resultHtml);

         if (editTab === 'continue') {
            if (lastNode.nextSibling) {
               parent.insertBefore(fragment, lastNode.nextSibling);
            } else {
               parent.appendChild(fragment);
            }
            startNode.removeAttribute('data-edit-id');
         } else {
            parent.insertBefore(fragment, firstNode);
            nodesToReplace.forEach(n => n.remove());
         }

      } else {
         const range = selectionRangeRef.current;
         if (range) {
             const fragment = range.createContextualFragment(resultHtml);
             range.deleteContents();
             range.insertNode(fragment);

             const selection = window.getSelection();
             selection?.removeAllRanges();
         }
      }

      setRewriteModalOpen(false);

      if (editorRef.current) {
        const rawContent = getCurrentHtml();
        setGeneratedHtml(rawContent);
        pushToHistory(rawContent);
        saveToStorage();
      }

    } catch (error) {
      if (!isResettingRef.current) {
        console.error("Rewrite failed:", error);
        alert("Failed to update content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setIsRewriting(false);
      }
    }
  };

  // --- RENDER ---

  if (!generatedHtml && status === GenerationStatus.IDLE) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
        <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl overflow-hidden animate-in fade-in zoom-in duration-300">

          <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-8 text-white text-center">
            <BookOpen className="w-12 h-12 mx-auto mb-4 opacity-90" />
            <h1 className="text-3xl font-bold mb-2">AI Book Writer</h1>
            <p className="opacity-90">Generate structured notes, books, and study guides instantly.</p>
          </div>

          <div className="p-8">
            <div className="bg-gray-100 p-1 rounded-xl flex mb-8 relative">
              <button
                onClick={() => setMode('topic')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-semibold transition-all duration-200 ${
                  mode === 'topic' ? 'bg-white text-blue-700 shadow-md' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <Sparkles className="w-4 h-4" />
                Generate from Topic
              </button>
              <button
                onClick={() => setMode('text')}
                className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-lg text-sm font-semibold transition-all duration-200 ${
                  mode === 'text' ? 'bg-white text-blue-700 shadow-md' : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <FileText className="w-4 h-4" />
                Format Existing Text
              </button>
            </div>

            <form onSubmit={handleGenerate} className="space-y-6">
              <div className="min-h-[120px]">
                {mode === 'topic' ? (
                  <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">What do you want to write about?</label>
                    <div className="relative">
                      <input 
                        type="text" 
                        value={topicInput}
                        onChange={(e) => setTopicInput(e.target.value)}
                        placeholder="e.g. History of India, Quantum Physics..."
                        className="w-full px-4 py-4 text-lg border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all bg-white text-gray-900 placeholder-gray-400"
                        autoFocus
                      />
                      <div className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none"><Sparkles className="w-5 h-5" /></div>
                    </div>
                  </div>
                ) : (
                  <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Paste your text here</label>
                    <textarea 
                      value={textInput}
                      onChange={(e) => setTextInput(e.target.value)}
                      placeholder="Paste unstructured notes..."
                      className="w-full h-64 px-4 py-4 text-base border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 outline-none resize-none transition-all bg-white text-gray-900 placeholder-gray-400"
                    />
                  </div>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                 <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase tracking-wide mb-1.5">Output Language</label>
                    <select 
                      value={language} 
                      onChange={(e) => setLanguage(e.target.value)}
                      className="w-full px-4 py-3 bg-white border border-gray-200 rounded-lg text-gray-900 focus:ring-2 focus:ring-blue-500 outline-none"
                    >
                      <option value="Hindi">Hindi (हिन्दी)</option>
                      <option value="English">English</option>
                      <option value="Hinglish">Hinglish</option>
                    </select>
                 </div>
                 <div className="flex items-end">
                    <Button type="submit" className="w-full py-3.5 text-base font-bold shadow-lg shadow-blue-500/30 hover:shadow-blue-500/50 transition-all transform active:scale-95">
                      {mode === 'topic' ? 'Generate Book Chapter' : 'Format & Structure Text'}
                    </Button>
                 </div>
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

  if (status !== GenerationStatus.IDLE) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
        <div className="w-20 h-20 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-8"></div>
        <h2 className="text-2xl font-bold text-gray-800 animate-pulse">
          {mode === 'topic' ? 'Writing your book...' : 'Organizing your notes...'}
        </h2>
        <div className="mt-4 space-y-2 text-center text-gray-500">
           <p>Designing layout</p>
           <p>Creating flowcharts</p>
           <p>Formatting tables</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-gray-200 overflow-hidden font-sans">

      <header className="bg-white border-b border-gray-300 h-16 flex items-center justify-between px-4 lg:px-8 shadow-sm z-20 no-print">
        <div className="flex items-center gap-4">
          <Button 
            onClick={handleRestartApp} 
            variant="secondary"
            className="flex items-center gap-2 text-sm font-semibold border-gray-300 hover:bg-gray-100 hover:text-blue-600 transition-all"
          >
            <Plus className="w-4 h-4" /> New
          </Button>

          <div className="h-6 w-px bg-gray-300 hidden sm:block"></div>
          <span className="font-serif font-bold text-gray-800 hidden sm:block truncate max-w-[200px] lg:max-w-[400px]">
            {mode === 'topic' ? (topicInput || 'Untitled') : 'Formatted Notes'}
          </span>
          <span className="hidden lg:flex text-xs text-green-600 bg-green-50 px-2 py-1 rounded-full items-center gap-1 opacity-80">
            <Save className="w-3 h-3" /> Auto-saved
          </span>
        </div>

        <div className="flex items-center gap-2 sm:gap-3">
          {/* HISTORY CONTROLS */}
          <div className="flex items-center bg-gray-100 rounded-lg p-1 mr-1 sm:mr-2">
             <Button 
                variant="ghost" 
                onClick={handleUndo} 
                disabled={historyIndex <= 0}
                className={`p-1.5 h-8 w-8 rounded-md transition-all ${historyIndex <= 0 ? '!text-gray-400' : '!text-gray-900 hover:bg-white hover:shadow-sm'}`}
                title="Undo"
             >
                <Undo className="w-4 h-4" />
             </Button>
             <div className="w-px h-4 bg-gray-300 mx-1"></div>
             <Button 
                variant="ghost" 
                onClick={handleRedo} 
                disabled={historyIndex >= history.length - 1}
                className={`p-1.5 h-8 w-8 rounded-md transition-all ${historyIndex >= history.length - 1 ? '!text-gray-400' : '!text-gray-900 hover:bg-white hover:shadow-sm'}`}
                title="Redo"
             >
                <Redo className="w-4 h-4" />
             </Button>
          </div>

          {isEditing ? (
             <div className="flex items-center gap-2 animate-in fade-in duration-200">
                <Button 
                  variant="ghost" 
                  onClick={openSelectionRewriteModal} 
                  icon={<Wand2 className="w-4 h-4 text-purple-600"/>}
                  className="text-sm border border-purple-200 bg-purple-50 text-purple-700 hover:bg-purple-100 hidden sm:flex"
                >
                  <span className="hidden sm:inline">Rewrite</span>
                </Button>
                {/* Mobile Icon Only for Rewrite */}
                <Button 
                  variant="ghost" 
                  onClick={openSelectionRewriteModal} 
                  className="text-sm border border-purple-200 bg-purple-50 text-purple-700 hover:bg-purple-100 sm:hidden p-2"
                >
                  <Wand2 className="w-4 h-4" />
                </Button>

                <Button variant="primary" onClick={handleSaveContent} icon={<Check className="w-4 h-4"/>} className="bg-green-600 hover:bg-green-700 text-sm">
                  <span className="hidden sm:inline">Done</span>
                </Button>
             </div>
          ) : (
             <Button variant="secondary" onClick={() => setIsEditing(true)} icon={<PenTool className="w-4 h-4"/>} className="text-sm">
               <span className="hidden sm:inline">Edit</span>
             </Button>
          )}

          <div className="h-6 w-px bg-gray-300 mx-1 hidden sm:block"></div>

          <Button variant="primary" onClick={handleExportPDF} icon={<Printer className="w-4 h-4"/>} className="text-sm shadow-sm">
            <span className="hidden sm:inline">Print</span>
          </Button>
          <Button variant="ghost" onClick={handleRestartApp} className="text-red-500 hover:bg-red-50 p-2 sm:hidden">
            <Plus className="w-5 h-5" />
          </Button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 flex justify-center bg-gray-200/80">
        <div className="w-full max-w-[210mm] transition-all duration-300">

           <div className="editor-container a4-page shadow-2xl editor-content bg-white"
             style={{ minHeight: '297mm' }}
           >
              <div 
                className={`min-h-[250mm] outline-none ${isEditing ? 'cursor-text' : ''}`}
                contentEditable={isEditing}
                suppressContentEditableWarning={true}
                ref={editorRef}
                onInput={handleEditorInput}
                onBlur={handleEditorBlur}
                dangerouslySetInnerHTML={{ __html: generatedHtml || '' }}
              />
           </div>
           <div className="text-center mt-6 mb-12 text-gray-500 text-sm font-medium no-print">End of Document</div>
        </div>
      </main>

      {rewriteModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in duration-200">

              <div className="flex items-center justify-between mb-4">
                 <h3 className="text-lg font-bold flex items-center gap-2">
                    {rewriteType === 'section' ? <Sparkles className="w-5 h-5 text-blue-600"/> : <Wand2 className="w-5 h-5 text-purple-600"/>}
                    {rewriteType === 'section' ? 'Magic AI Editor' : 'Rewrite Selection'}
                 </h3>
                 <button onClick={() => setRewriteModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                   <ArrowLeft className="w-5 h-5 rotate-180" />
                 </button>
              </div>

              <div className="flex p-1 bg-gray-100 rounded-lg mb-4">
                  <button 
                     onClick={() => setEditTab('rewrite')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'rewrite' ? 'bg-white shadow text-purple-700' : 'text-gray-500'}`}
                  >
                      Rewrite
                  </button>
                  <button 
                     onClick={() => setEditTab('expand')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'expand' ? 'bg-white shadow text-blue-700' : 'text-gray-500'}`}
                  >
                      Expand (Deep Dive)
                  </button>
                  <button 
                     onClick={() => setEditTab('continue')}
                     className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${editTab === 'continue' ? 'bg-white shadow text-green-700' : 'text-gray-500'}`}
                  >
                      {rewriteType === 'section' ? 'Add After' : 'Continue'}
                  </button>
              </div>

              <div className="mb-4 text-sm text-gray-500 bg-gray-50 p-3 rounded-lg border border-gray-100 max-h-32 overflow-y-auto">
                 <strong>Editing context:</strong>
                 <div className="italic mt-1 text-xs opacity-70">
                    {rewriteType === 'section' 
                       ? "Selected Heading + Sub-content."
                       : selectionRangeRef.current?.toString().substring(0, 100) + "..."
                    }
                 </div>
              </div>

              <form onSubmit={handleRewriteSubmit}>
                 <label className="block text-sm text-gray-600 mb-2">Instruction</label>
                 <input 
                   type="text" 
                   value={rewriteInstruction}
                   onChange={(e) => setRewriteInstruction(e.target.value)}
                   placeholder={
                       editTab === 'expand' ? "e.g. Explain Article 14, 15 separately with details..." :
                       editTab === 'continue' ? "e.g. Write the next 3 sub-points about..." :
                       "e.g. Fix grammar, make it shorter..."
                   }
                   className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 outline-none bg-white text-gray-900"
                   autoFocus
                 />
                 <div className="flex justify-end gap-3">
                    <Button type="button" variant="secondary" onClick={() => setRewriteModalOpen(false)} disabled={isRewriting}>
                        Cancel
                    </Button>
                    <Button 
                        type="submit" 
                        className={`text-white shadow-lg transition-colors ${
                            editTab === 'expand' ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-500/30' :
                            editTab === 'continue' ? 'bg-green-600 hover:bg-green-700 shadow-green-500/30' :
                            'bg-purple-600 hover:bg-purple-700 shadow-purple-500/30'
                        }`} 
                        isLoading={isRewriting}
                    >
                        {editTab === 'expand' ? 'Expand Content' : editTab === 'continue' ? 'Generate Next' : 'Rewrite'}
                    </Button>
                 </div>
              </form>
           </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  generateTopicContent, 
  generateFormattedNotes, 
  rewriteContent, 
  rewriteSection,
  expandSection,
  generateNextContent
} from './services/ai';
import { GenerationStatus } from './types';
import { Button } from './components/Button';
import { 
  BookOpen, 
  PenTool, 
  Printer, 
  Sparkles,
  FileText,
  Trash2,
  Wand2,
  ArrowLeft,
  Check,
  Save,
  Undo,
  Redo,
  RefreshCw,
  Plus,
  PanelLeftClose,
  PanelLeft,
  Download,
  Eraser
} from 'lucide-react';

const STORAGE_KEY = 'ai_book_writer_draft';

const App: React.FC = () => {
  // --- UI STATE ---
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // --- GENERATION STATE ---
  const [mode, setMode] = useState<'topic' | 'text'>('topic');
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [language, setLanguage] = useState('Hindi'); 
  const [topicInput, setTopicInput] = useState('');
  const [textInput, setTextInput] = useState('');

  // --- EDITOR STATE ---
  const [isEditing, setIsEditing] = useState(false);
  const [generatedHtml, setGeneratedHtml] = useState<string | null>(null);
  const editorRef = useRef<HTMLDivElement>(null);

  // --- HISTORY STATE ---
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const historyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // --- REWRITE STATE ---
  const isResettingRef = useRef(false);
  const [rewriteModalOpen, setRewriteModalOpen] = useState(false);
  const [rewriteInstruction, setRewriteInstruction] = useState('');
  const [isRewriting, setIsRewriting] = useState(false);
  const selectionRangeRef = useRef<Range | null>(null);
  const activeEditIdRef = useRef<string | null>(null);
  const [activeSectionHtml, setActiveSectionHtml] = useState<string>('');
  const [rewriteType, setRewriteType] = useState<'selection' | 'section'>('selection');
  const [editTab, setEditTab] = useState<'rewrite' | 'expand' | 'continue'>('rewrite');

  // --- 1. INITIALIZATION & HISTORY ---

  const pushToHistory = useCallback((content: string) => {
    setHistory(prev => {
      if (historyIndex >= 0 && prev[historyIndex] === content) return prev;
      const newHistory = prev.slice(0, historyIndex + 1);
      return [...newHistory, content];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  useEffect(() => {
    const savedContent = localStorage.getItem(STORAGE_KEY);
    if (savedContent) {
      setGeneratedHtml(savedContent);
      setHistory([savedContent]);
      setHistoryIndex(0);
    }
  }, []);

  // --- 2. EDITOR HELPERS ---

  const getCurrentHtml = useCallback(() => {
    return editorRef.current ? editorRef.current.innerHTML : (generatedHtml || '');
  }, [generatedHtml]);

  const getCleanHtml = useCallback(() => {
    if (!editorRef.current) return generatedHtml || '';
    const clone = editorRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll('.ai-edit-trigger').forEach(b => b.remove());
    clone.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    return clone.innerHTML;
  }, [generatedHtml]);

  const saveToStorage = useCallback(() => {
    if (isResettingRef.current) return;
    const content = getCleanHtml();
    if (content) {
      localStorage.setItem(STORAGE_KEY, content);
    }
    return content;
  }, [getCleanHtml]);

  // Auto-save logic
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') saveToStorage();
    };
    const intervalId = setInterval(() => { if (isEditing) saveToStorage(); }, 5000);
    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('pagehide', saveToStorage);
    window.addEventListener('beforeunload', saveToStorage);
    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', saveToStorage);
      window.removeEventListener('beforeunload', saveToStorage);
      clearInterval(intervalId);
    };
  }, [saveToStorage, isEditing]);

  const handleEditorInput = () => {
    if (isResettingRef.current) return;
    if (historyTimeoutRef.current) clearTimeout(historyTimeoutRef.current);
    historyTimeoutRef.current = setTimeout(() => {
       if (isResettingRef.current) return;
       const rawContent = getCurrentHtml(); 
       setGeneratedHtml(rawContent); 
       pushToHistory(rawContent);
       saveToStorage();
    }, 800);
  };

  const handleEditorBlur = () => {
      if (isResettingRef.current) return;
      const rawContent = getCurrentHtml();
      setGeneratedHtml(rawContent);
  };

  // --- 3. CORE GENERATION LOGIC ---

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'topic' && !topicInput.trim()) return;
    if (mode === 'text' && !textInput.trim()) return;

    setStatus(GenerationStatus.GENERATING_CHAPTER);

    try {
      let result = "";
      if (mode === 'topic') {
        result = await generateTopicContent(topicInput, language);
      } else {
        result = await generateFormattedNotes(textInput, language);
      }

      if (isResettingRef.current) return;

      // Ensure we push new content properly
      setGeneratedHtml(result);
      setHistory(prev => [...prev, result]);
      setHistoryIndex(prev => prev.length); // Correctly point to new end
      localStorage.setItem(STORAGE_KEY, result); 

      // Auto-save input to history if user wants to recall? (Optional, skipping for now)

    } catch (error) {
      if (!isResettingRef.current) {
        console.error(error);
        alert("Error generating content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setStatus(GenerationStatus.IDLE);
      }
    }
  };

  const handleClearCanvas = () => {
    if(!confirm("Are you sure you want to clear the editor?")) return;
    isResettingRef.current = true;
    setGeneratedHtml(null);
    setHistory([]);
    setHistoryIndex(-1);
    setIsEditing(false);
    activeEditIdRef.current = null;
    selectionRangeRef.current = null;
    localStorage.removeItem(STORAGE_KEY);
    setTimeout(() => { isResettingRef.current = false; }, 100);
  };

  // --- 4. REWRITE & EDIT LOGIC (Simplified for Length) ---

  // (Helper for edit buttons)
  const getSectionNodes = (startNode: Element): Element[] => {
    const nodes: Element[] = [startNode];
    const tagName = startNode.tagName;
    const getLevel = (tag: string) => {
      const t = tag.toUpperCase();
      if (t === 'H1') return 1;
      if (t === 'H2') return 2;
      if (t === 'H3') return 3;
      if (t === 'H4') return 4;
      return 10; 
    };
    const currentLevel = getLevel(tagName);
    if (currentLevel <= 4) {
      let nextSibling = startNode.nextElementSibling;
      while (nextSibling) {
        const nextTag = nextSibling.tagName;
        const nextLevel = getLevel(nextTag);
        if (nextLevel <= currentLevel) break;
        nodes.push(nextSibling);
        nextSibling = nextSibling.nextElementSibling;
      }
    } 
    return nodes;
  };

  // Inject buttons
  useEffect(() => {
    if (!editorRef.current) return;
    if (isEditing) {
      const elements = editorRef.current.querySelectorAll('h1, h2, h3, h4, li');
      elements.forEach((el) => {
        if (el.querySelector('.ai-edit-trigger')) return;
        const btn = document.createElement('span');
        btn.contentEditable = "false";
        btn.className = "ai-edit-trigger no-print";
        btn.innerHTML = "✨";
        btn.title = "Rewrite/Expand";
        if (el.tagName === 'LI') el.insertBefore(btn, el.firstChild);
        else el.appendChild(btn);
      });
    } else {
      editorRef.current.querySelectorAll('.ai-edit-trigger').forEach(btn => btn.remove());
    }
  }, [isEditing, generatedHtml]);

  // Click Handler for Edit Buttons
  useEffect(() => {
    const handleEditorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.classList.contains('ai-edit-trigger')) {
        e.preventDefault();
        e.stopPropagation();
        const parentEl = target.parentElement;
        if (parentEl) handleSectionEdit(parentEl);
      }
    };
    const editor = editorRef.current;
    if (editor) editor.addEventListener('click', handleEditorClick);
    return () => { if (editor) editor.removeEventListener('click', handleEditorClick); };
  }, [isEditing]);

  const handleSectionEdit = (startNode: Element) => {
    if (!editorRef.current) return;
    const currentRaw = getCurrentHtml();
    pushToHistory(currentRaw);
    setGeneratedHtml(currentRaw);

    const editId = `edit-${Date.now()}`;
    editorRef.current.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    startNode.setAttribute('data-edit-id', editId);
    activeEditIdRef.current = editId;

    const nodes = getSectionNodes(startNode);
    const tempDiv = document.createElement('div');
    nodes.forEach(node => {
        const clone = node.cloneNode(true) as Element;
        const trigger = clone.querySelector('.ai-edit-trigger');
        if(trigger) trigger.remove();
        clone.removeAttribute('data-edit-id'); 
        tempDiv.appendChild(clone);
    });
    setActiveSectionHtml(tempDiv.innerHTML);
    setGeneratedHtml(editorRef.current.innerHTML); 
    setRewriteType('section');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const openSelectionRewriteModal = () => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.toString().trim().length === 0) {
      alert("Please select text to rewrite.");
      return;
    }
    selectionRangeRef.current = selection.getRangeAt(0);
    setRewriteType('selection');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const handleRewriteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsRewriting(true);
    try {
      const rawBefore = getCurrentHtml();
      pushToHistory(rawBefore);
      let resultHtml = "";

      if (rewriteType === 'section') {
         if (editTab === 'rewrite') resultHtml = await rewriteSection(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'expand') resultHtml = await expandSection(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'continue') resultHtml = await generateNextContent(activeSectionHtml, rewriteInstruction);
      } else {
         const selectedText = selectionRangeRef.current?.toString() || "";
         if (editTab === 'rewrite') resultHtml = await rewriteContent(selectedText, rewriteInstruction);
         else if (editTab === 'expand') resultHtml = await expandSection(selectedText, rewriteInstruction);
         else if (editTab === 'continue') {
             const nextContent = await generateNextContent(selectedText, rewriteInstruction);
             resultHtml = selectedText + " " + nextContent;
         }
      }

      if (isResettingRef.current) return;
      if (!resultHtml) throw new Error("No content generated");

      // DOM Replacement Logic
      if (rewriteType === 'section') {
         const editId = activeEditIdRef.current;
         if (!editorRef.current || !editId) throw new Error("Editor context lost.");
         const startNode = editorRef.current.querySelector(`[data-edit-id="${editId}"]`);
         if (!startNode) throw new Error("Lost position.");
         const nodesToReplace = getSectionNodes(startNode);
         const firstNode = nodesToReplace[0];
         const lastNode = nodesToReplace[nodesToReplace.length - 1];
         const parent = firstNode.parentNode;
         if (!parent) throw new Error("Parent node lost.");

         const range = document.createRange();
         range.setStartBefore(firstNode);
         const fragment = range.createContextualFragment(resultHtml);

         if (editTab === 'continue') {
            if (lastNode.nextSibling) parent.insertBefore(fragment, lastNode.nextSibling);
            else parent.appendChild(fragment);
            startNode.removeAttribute('data-edit-id');
         } else {
            parent.insertBefore(fragment, firstNode);
            nodesToReplace.forEach(n => n.remove());
         }
      } else {
         const range = selectionRangeRef.current;
         if (range) {
             const fragment = range.createContextualFragment(resultHtml);
             range.deleteContents();
             range.insertNode(fragment);
             const selection = window.getSelection();
             selection?.removeAllRanges();
         }
      }
      setRewriteModalOpen(false);
      if (editorRef.current) {
        const rawContent = getCurrentHtml();
        setGeneratedHtml(rawContent);
        pushToHistory(rawContent);
        saveToStorage();
      }
    } catch (error) {
      if (!isResettingRef.current) {
        console.error("Rewrite failed:", error);
        alert("Failed. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) setIsRewriting(false);
    }
  };

  // --- 5. PDF EXPORT ---
  const handleExportPDF = () => {
    if (!generatedHtml) return;
    const contentToPrint = isEditing && editorRef.current ? getCleanHtml() : generatedHtml;
    const printWindow = window.open('', '_blank');
    if (!printWindow) { alert("Enable pop-ups."); return; }

    // Using strict print CSS embedded here for the popup
    const content = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
          <meta charset="UTF-8">
          <title>Export Notes</title>
          <link href="https://fonts.googleapis.com/css2?family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Inter:wght@400;600;800&display=swap" rel="stylesheet">
          <style>
              @page { size: A4; margin: 5mm; }
              body { font-family: 'Merriweather', serif; font-size: 10pt; line-height: 1.4; color: #000; background: white; margin: 0; padding: 0; }
              h1 { font-family: 'Inter', sans-serif; font-size: 20pt; font-weight: 800; color: #000; border-bottom: 3px solid #000; padding-bottom: 5px; margin-top: 0; margin-bottom: 15px; page-break-after: avoid; }
              h2 { font-family: 'Inter', sans-serif; font-size: 14pt; font-weight: 700; color: #000; margin-top: 15px; margin-bottom: 8px; page-break-after: avoid; border-bottom: 1px solid #ddd; }
              h3 { font-family: 'Inter', sans-serif; font-size: 12pt; font-weight: 600; color: #000; margin-top: 10px; margin-bottom: 5px; page-break-after: avoid; }
              p { margin-bottom: 8px; text-align: justify; }
              ul, ol { margin-bottom: 10px; padding-left: 20px; }
              li { margin-bottom: 2px; }
              table { width: 100%; border-collapse: collapse; margin: 15px 0; border: 2px solid #000; page-break-inside: avoid; font-size: 9pt; }
              th { background-color: #f0f0f0; border: 1px solid #000; padding: 4px 8px; font-weight: bold; text-align: left; font-family: 'Inter', sans-serif; font-size: 9pt; }
              td { border: 1px solid #000; padding: 4px 8px; font-size: 9pt; vertical-align: top; }
              .flowchart-container { display: flex; justify-content: center; margin: 15px 0; padding: 5px; border: 1px dashed #ccc; page-break-inside: avoid; }
              svg { max-width: 100%; height: auto; }
              @media print {
                  body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                  .no-print { display: none; }
                  h1, h2, h3 { page-break-after: avoid; }
                  table, .flowchart-container { page-break-inside: avoid; }
                  p { orphans: 3; widows: 3; }
              }
          </style>
      </head>
      <body>
          ${contentToPrint}
          <script>
              window.onload = function() { setTimeout(function() { window.print(); }, 800); }
          </script>
      </body>
      </html>
    `;
    printWindow.document.open();
    printWindow.document.write(content);
    printWindow.document.close();
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setGeneratedHtml(history[newIndex]);
      setHistoryIndex(newIndex);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setGeneratedHtml(history[newIndex]);
      setHistoryIndex(newIndex);
    }
  };

  // --- RENDER ---
  return (
    <div className="flex h-screen w-full bg-gray-100 text-gray-900 font-sans overflow-hidden">

      {/* --- SIDEBAR (INPUT) --- */}
      <aside 
        className={`${sidebarOpen ? 'w-full md:w-96 translate-x-0' : 'w-0 -translate-x-full'} 
          fixed md:relative z-30 h-full bg-[#1e293b] text-white transition-all duration-300 ease-in-out flex flex-col border-r border-gray-700 shadow-2xl`}
      >
        <div className="p-5 border-b border-gray-700 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <BookOpen className="w-6 h-6 text-blue-400" />
                <h1 className="text-xl font-bold tracking-tight">AI Book Writer</h1>
            </div>
            <button onClick={() => setSidebarOpen(false)} className="md:hidden text-gray-400 hover:text-white">
                <PanelLeftClose className="w-5 h-5"/>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-5 scrollbar-thin scrollbar-thumb-gray-600">
            {/* TABS */}
            <div className="flex bg-slate-800 p-1 rounded-lg mb-6 border border-slate-700">
                <button 
                   onClick={() => setMode('topic')}
                   className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm font-medium transition-all ${mode === 'topic' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
                >
                    <Sparkles className="w-4 h-4" /> Topic
                </button>
                <button 
                   onClick={() => setMode('text')}
                   className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm font-medium transition-all ${mode === 'text' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
                >
                    <FileText className="w-4 h-4" /> Text
                </button>
            </div>

            <form onSubmit={handleGenerate} className="space-y-5">
                {mode === 'topic' ? (
                   <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Book Topic</label>
                      <input 
                         type="text"
                         value={topicInput}
                         onChange={(e) => setTopicInput(e.target.value)}
                         placeholder="e.g. History of India..."
                         className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
                      />
                   </div>
                ) : (
                   <div>
                      <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Raw Content</label>
                      <textarea 
                         value={textInput}
                         onChange={(e) => setTextInput(e.target.value)}
                         placeholder="Paste notes here..."
                         className="w-full h-40 bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all resize-none"
                      />
                   </div>
                )}

                <div>
                    <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">Language</label>
                    <select 
                      value={language}
                      onChange={(e) => setLanguage(e.target.value)}
                      className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                        <option value="Hindi">Hindi</option>
                        <option value="English">English</option>
                        <option value="Hinglish">Hinglish</option>
                    </select>
                </div>

                <Button 
                   type="submit" 
                   className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-xl shadow-lg shadow-blue-900/20 transform transition-all active:scale-95"
                   isLoading={status === GenerationStatus.GENERATING_CHAPTER}
                >
                    {mode === 'topic' ? 'Generate Chapter' : 'Format Notes'}
                </Button>
            </form>

            <div className="mt-8 pt-6 border-t border-slate-700">
                <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4">Actions</h3>
                <div className="grid grid-cols-2 gap-3">
                   <button onClick={handleClearCanvas} className="flex items-center justify-center gap-2 p-3 rounded-lg bg-slate-800 text-red-400 hover:bg-slate-700 hover:text-red-300 transition-colors border border-slate-700 text-sm font-medium">
                       <Eraser className="w-4 h-4" /> Clear All
                   </button>
                   <button onClick={() => setGeneratedHtml(history[historyIndex - 1])} disabled={historyIndex <= 0} className="flex items-center justify-center gap-2 p-3 rounded-lg bg-slate-800 text-slate-300 hover:bg-slate-700 transition-colors border border-slate-700 text-sm font-medium disabled:opacity-50">
                       <Undo className="w-4 h-4" /> Undo
                   </button>
                </div>
            </div>
        </div>

        <div className="p-4 bg-slate-900 border-t border-slate-800 text-xs text-slate-500 text-center">
            AI Book Writer v2.0
        </div>
      </aside>

      {/* --- MAIN AREA (EDITOR) --- */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">

         {/* TOP TOOLBAR */}
         <div className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm z-20">
             <div className="flex items-center gap-4">
                 <button 
                   onClick={() => setSidebarOpen(!sidebarOpen)}
                   className="p-2 rounded-lg hover:bg-gray-100 text-gray-600 transition-colors"
                 >
                    {sidebarOpen ? <PanelLeftClose className="w-5 h-5" /> : <PanelLeft className="w-5 h-5" />}
                 </button>
                 <div className="h-6 w-px bg-gray-300"></div>
                 <div className="flex items-center gap-1 bg-gray-100 rounded-md p-1">
                    <button onClick={handleUndo} disabled={historyIndex <= 0} className="p-1.5 rounded hover:bg-white hover:shadow-sm text-gray-600 disabled:opacity-30"><Undo className="w-4 h-4"/></button>
                    <button onClick={handleRedo} disabled={historyIndex >= history.length - 1} className="p-1.5 rounded hover:bg-white hover:shadow-sm text-gray-600 disabled:opacity-30"><Redo className="w-4 h-4"/></button>
                 </div>
             </div>

             <div className="flex items-center gap-3">
                {isEditing ? (
                  <>
                     <Button variant="ghost" onClick={openSelectionRewriteModal} className="text-purple-600 bg-purple-50 hover:bg-purple-100 border-purple-200">
                        <Wand2 className="w-4 h-4 mr-2" /> Rewrite
                     </Button>
                     <Button variant="primary" onClick={() => { setIsEditing(false); saveToStorage(); }} className="bg-green-600 hover:bg-green-700">
                        <Check className="w-4 h-4 mr-2" /> Done
                     </Button>
                  </>
                ) : (
                  <Button variant="secondary" onClick={() => setIsEditing(true)}>
                    <PenTool className="w-4 h-4 mr-2" /> Edit Mode
                  </Button>
                )}

                <div className="h-6 w-px bg-gray-300"></div>

                <Button variant="primary" onClick={handleExportPDF}>
                   <Printer className="w-4 h-4 mr-2" /> Print PDF
                </Button>
             </div>
         </div>

         {/* CANVAS AREA */}
         <div className="flex-1 overflow-y-auto bg-gray-200/50 p-8 flex justify-center relative">
             {status !== GenerationStatus.IDLE && (
                <div className="absolute inset-0 bg-white/80 backdrop-blur-sm z-50 flex flex-col items-center justify-center">
                    <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-lg font-bold text-gray-800 animate-pulse">Generating your masterpiece...</p>
                </div>
             )}

             <div className={`w-full max-w-[210mm] transition-all duration-500 ${!generatedHtml && status === GenerationStatus.IDLE ? 'opacity-50' : 'opacity-100'}`}>
                 <div className="editor-container a4-page shadow-xl editor-content bg-white min-h-[297mm]">
                    {!generatedHtml && status === GenerationStatus.IDLE ? (
                        <div className="h-[297mm] flex flex-col items-center justify-center text-gray-400 border-2 border-dashed border-gray-200 rounded-lg m-8">
                            <BookOpen className="w-16 h-16 mb-4 opacity-20" />
                            <p className="text-xl font-medium">Ready to write</p>
                            <p className="text-sm mt-2">Use the sidebar to generate content</p>
                        </div>
                    ) : (
                        <div 
                            className={`min-h-[287mm] outline-none ${isEditing ? 'cursor-text' : ''}`}
                            contentEditable={isEditing}
                            suppressContentEditableWarning={true}
                            ref={editorRef}
                            onInput={handleEditorInput}
                            onBlur={handleEditorBlur}
                            dangerouslySetInnerHTML={{ __html: generatedHtml || '' }}
                        />
                    )}
                 </div>
                 <div className="h-12"></div> {/* Bottom spacer */}
             </div>
         </div>

      </main>

      {/* --- REWRITE MODAL --- */}
      {rewriteModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in duration-200">
              <div className="flex items-center justify-between mb-4">
                 <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
                    {rewriteType === 'section' ? <Sparkles className="w-5 h-5 text-blue-600"/> : <Wand2 className="w-5 h-5 text-purple-600"/>}
                    {rewriteType === 'section' ? 'Magic AI Editor' : 'Rewrite Selection'}
                 </h3>
                 <button onClick={() => setRewriteModalOpen(false)} className="text-gray-400 hover:text-gray-600"><ArrowLeft className="w-5 h-5 rotate-180" /></button>
              </div>

              <div className="flex p-1 bg-gray-100 rounded-lg mb-4">
                  {(['rewrite', 'expand', 'continue'] as const).map(tab => (
                      <button 
                        key={tab}
                        onClick={() => setEditTab(tab)}
                        className={`flex-1 py-1.5 text-xs font-semibold rounded-md capitalize transition-all ${editTab === tab ? 'bg-white shadow text-blue-700' : 'text-gray-500'}`}
                      >
                          {tab === 'expand' ? 'Deep Dive' : tab}
                      </button>
                  ))}
              </div>

              <div className="mb-4 text-sm text-gray-500 bg-gray-50 p-3 rounded-lg border border-gray-100 max-h-32 overflow-y-auto">
                 <strong>Context:</strong>
                 <div className="italic mt-1 text-xs opacity-70">
                    {rewriteType === 'section' ? "Selected Section" : selectionRangeRef.current?.toString().substring(0, 100) + "..."}
                 </div>
              </div>

              <form onSubmit={handleRewriteSubmit}>
                 <label className="block text-sm text-gray-600 mb-2">Instruction</label>
                 <input 
                   type="text" 
                   value={rewriteInstruction}
                   onChange={(e) => setRewriteInstruction(e.target.value)}
                   placeholder="e.g. Add examples, fix grammar..."
                   className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 mb-6 outline-none bg-white text-gray-900"
                   autoFocus
                 />
                 <div className="flex justify-end gap-3">
                    <Button type="button" variant="secondary" onClick={() => setRewriteModalOpen(false)} disabled={isRewriting}>Cancel</Button>
                    <Button type="submit" isLoading={isRewriting} className="bg-blue-600 text-white">Apply</Button>
                 </div>
              </form>
           </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  generateTopicContent, 
  generateFormattedNotes, 
  rewriteContent, 
  rewriteSection,
  expandSection,
  generateNextContent
} from './services/ai';
import { GenerationStatus } from './types';
import { Button } from './components/Button';
import { 
  BookOpen, 
  PenTool, 
  Printer, 
  Sparkles,
  FileText,
  Trash2,
  Wand2,
  ArrowLeft,
  Check,
  Save,
  Undo,
  Redo,
  RefreshCw,
  Plus,
  PanelLeftClose,
  PanelLeft,
  Download,
  Eraser
} from 'lucide-react';

const STORAGE_KEY = 'ai_book_writer_draft';

const App: React.FC = () => {
  // --- UI STATE ---
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // --- GENERATION STATE ---
  const [mode, setMode] = useState<'topic' | 'text'>('topic');
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [language, setLanguage] = useState('Hindi'); 
  const [topicInput, setTopicInput] = useState('');
  const [textInput, setTextInput] = useState('');

  // --- EDITOR STATE ---
  const [isEditing, setIsEditing] = useState(false);
  const [generatedHtml, setGeneratedHtml] = useState<string | null>(null);
  const editorRef = useRef<HTMLDivElement>(null);

  // --- HISTORY STATE ---
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const historyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // --- REWRITE STATE ---
  const isResettingRef = useRef(false);
  const [rewriteModalOpen, setRewriteModalOpen] = useState(false);
  const [rewriteInstruction, setRewriteInstruction] = useState('');
  const [isRewriting, setIsRewriting] = useState(false);
  const selectionRangeRef = useRef<Range | null>(null);
  const activeEditIdRef = useRef<string | null>(null);
  const [activeSectionHtml, setActiveSectionHtml] = useState<string>('');
  const [rewriteType, setRewriteType] = useState<'selection' | 'section'>('selection');
  const [editTab, setEditTab] = useState<'rewrite' | 'expand' | 'continue'>('rewrite');

  // --- 1. INITIALIZATION & HISTORY ---

  const pushToHistory = useCallback((content: string) => {
    setHistory(prev => {
      if (historyIndex >= 0 && prev[historyIndex] === content) return prev;
      const newHistory = prev.slice(0, historyIndex + 1);
      return [...newHistory, content];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  useEffect(() => {
    const savedContent = localStorage.getItem(STORAGE_KEY);
    if (savedContent) {
      setGeneratedHtml(savedContent);
      setHistory([savedContent]);
      setHistoryIndex(0);
    }
  }, []);

  // --- 2. EDITOR HELPERS ---

  const getCurrentHtml = useCallback(() => {
    return editorRef.current ? editorRef.current.innerHTML : (generatedHtml || '');
  }, [generatedHtml]);

  const getCleanHtml = useCallback(() => {
    if (!editorRef.current) return generatedHtml || '';
    const clone = editorRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll('.ai-edit-trigger').forEach(b => b.remove());
    clone.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    return clone.innerHTML;
  }, [generatedHtml]);

  const saveToStorage = useCallback(() => {
    if (isResettingRef.current) return;
    const content = getCleanHtml();
    if (content) {
      localStorage.setItem(STORAGE_KEY, content);
    }
    return content;
  }, [getCleanHtml]);

  // Auto-save logic
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') saveToStorage();
    };
    const intervalId = setInterval(() => { if (isEditing) saveToStorage(); }, 5000);
    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('pagehide', saveToStorage);
    window.addEventListener('beforeunload', saveToStorage);
    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', saveToStorage);
      window.removeEventListener('beforeunload', saveToStorage);
      clearInterval(intervalId);
    };
  }, [saveToStorage, isEditing]);

  const handleEditorInput = () => {
    if (isResettingRef.current) return;
    if (historyTimeoutRef.current) clearTimeout(historyTimeoutRef.current);
    historyTimeoutRef.current = setTimeout(() => {
       if (isResettingRef.current) return;
       const rawContent = getCurrentHtml(); 
       setGeneratedHtml(rawContent); 
       pushToHistory(rawContent);
       saveToStorage();
    }, 800);
  };

  const handleEditorBlur = () => {
      if (isResettingRef.current) return;
      const rawContent = getCurrentHtml();
      setGeneratedHtml(rawContent);
  };

  // --- 3. CORE GENERATION LOGIC ---

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'topic' && !topicInput.trim()) return;
    if (mode === 'text' && !textInput.trim()) return;

    setStatus(GenerationStatus.GENERATING_CHAPTER);

    try {
      let result = "";
      if (mode === 'topic') {
        result = await generateTopicContent(topicInput, language);
      } else {
        result = await generateFormattedNotes(textInput, language);
      }

      if (isResettingRef.current) return;

      // Ensure we push new content properly
      setGeneratedHtml(result);
      pushToHistory(result);
      localStorage.setItem(STORAGE_KEY, result); 

      // Auto-save input to history if user wants to recall? (Optional, skipping for now)

    } catch (error) {
      if (!isResettingRef.current) {
        console.error(error);
        alert("Error generating content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setStatus(GenerationStatus.IDLE);
      }
    }
  };

  const handleClearCanvas = () => {
    if(!confirm("Are you sure you want to clear the editor?")) return;
    isResettingRef.current = true;
    setGeneratedHtml(null);
    setHistory([]);
    setHistoryIndex(-1);
    setIsEditing(false);
    activeEditIdRef.current = null;
    selectionRangeRef.current = null;
    localStorage.removeItem(STORAGE_KEY);
    setTimeout(() => { isResettingRef.current = false; }, 100);
  };

  // --- 4. REWRITE & EDIT LOGIC (Simplified for Length) ---

  // (Helper for edit buttons)
  const getSectionNodes = (startNode: Element): Element[] => {
    const nodes: Element[] = [startNode];
    const tagName = startNode.tagName;
    const getLevel = (tag: string) => {
      const t = tag.toUpperCase();
      if (t === 'H1') return 1;
      if (t === 'H2') return 2;
      if (t === 'H3') return 3;
      if (t === 'H4') return 4;
      return 10; 
    };
    const currentLevel = getLevel(tagName);
    if (currentLevel <= 4) {
      let nextSibling = startNode.nextElementSibling;
      while (nextSibling) {
        const nextTag = nextSibling.tagName;
        const nextLevel = getLevel(nextTag);
        if (nextLevel <= currentLevel) break;
        nodes.push(nextSibling);
        nextSibling = nextSibling.nextElementSibling;
      }
    } 
    return nodes;
  };

  // Inject buttons
  useEffect(() => {
    if (!editorRef.current) return;
    if (isEditing) {
      const elements = editorRef.current.querySelectorAll('h1, h2, h3, h4, li');
      elements.forEach((el) => {
        if (el.querySelector('.ai-edit-trigger')) return;
        const btn = document.createElement('span');
        btn.contentEditable = "false";
        btn.className = "ai-edit-trigger no-print";
        btn.innerHTML = "✨";
        btn.title = "Rewrite/Expand";
        if (el.tagName === 'LI') el.insertBefore(btn, el.firstChild);
        else el.appendChild(btn);
      });
    } else {
      editorRef.current.querySelectorAll('.ai-edit-trigger').forEach(btn => btn.remove());
    }
  }, [isEditing, generatedHtml]);

  // Click Handler for Edit Buttons
  useEffect(() => {
    const handleEditorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.classList.contains('ai-edit-trigger')) {
        e.preventDefault();
        e.stopPropagation();
        const parentEl = target.parentElement;
        if (parentEl) handleSectionEdit(parentEl);
      }
    };
    const editor = editorRef.current;
    if (editor) editor.addEventListener('click', handleEditorClick);
    return () => { if (editor) editor.removeEventListener('click', handleEditorClick); };
  }, [isEditing]);

  const handleSectionEdit = (startNode: Element) => {
    if (!editorRef.current) return;
    const currentRaw = getCurrentHtml();
    pushToHistory(currentRaw);
    setGeneratedHtml(currentRaw);

    const editId = `edit-${Date.now()}`;
    editorRef.current.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    startNode.setAttribute('data-edit-id', editId);
    activeEditIdRef.current = editId;

    const nodes = getSectionNodes(startNode);
    const tempDiv = document.createElement('div');
    nodes.forEach(node => {
        const clone = node.cloneNode(true) as Element;
        const trigger = clone.querySelector('.ai-edit-trigger');
        if(trigger) trigger.remove();
        clone.removeAttribute('data-edit-id'); 
        tempDiv.appendChild(clone);
    });
    setActiveSectionHtml(tempDiv.innerHTML);
    setGeneratedHtml(editorRef.current.innerHTML); 
    setRewriteType('section');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const openSelectionRewriteModal = () => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.toString().trim().length === 0) {
      alert("Please select text to rewrite.");
      return;
    }
    selectionRangeRef.current = selection.getRangeAt(0);
    setRewriteType('selection');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const handleRewriteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsRewriting(true);
    try {
      const rawBefore = getCurrentHtml();
      pushToHistory(rawBefore);
      let resultHtml = "";

      if (rewriteType === 'section') {
         if (editTab === 'rewrite') resultHtml = await rewriteSection(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'expand') resultHtml = await expandSection(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'continue') resultHtml = await generateNextContent(activeSectionHtml, rewriteInstruction);
      } else {
         const selectedText = selectionRangeRef.current?.toString() || "";
         if (editTab === 'rewrite') resultHtml = await rewriteContent(selectedText, rewriteInstruction);
         else if (editTab === 'expand') resultHtml = await expandSection(selectedText, rewriteInstruction);
         else if (editTab === 'continue') {
             const nextContent = await generateNextContent(selectedText, rewriteInstruction);
             resultHtml = selectedText + " " + nextContent;
         }
      }

      if (isResettingRef.current) return;
      if (!resultHtml) throw new Error("No content generated");

      // DOM Replacement Logic
      if (rewriteType === 'section') {
         const editId = activeEditIdRef.current;
         if (!editorRef.current || !editId) throw new Error("Editor context lost.");
         const startNode = editorRef.current.querySelector(`[data-edit-id="${editId}"]`);
         if (!startNode) throw new Error("Lost position.");
         const nodesToReplace = getSectionNodes(startNode);
         const firstNode = nodesToReplace[0];
         const lastNode = nodesToReplace[nodesToReplace.length - 1];
         const parent = firstNode.parentNode;
         if (!parent) throw new Error("Parent node lost.");

         const range = document.createRange();
         range.setStartBefore(firstNode);
         const fragment = range.createContextualFragment(resultHtml);

         if (editTab === 'continue') {
            if (lastNode.nextSibling) parent.insertBefore(fragment, lastNode.nextSibling);
            else parent.appendChild(fragment);
            startNode.removeAttribute('data-edit-id');
         } else {
            parent.insertBefore(fragment, firstNode);
            nodesToReplace.forEach(n => n.remove());
         }
      } else {
         const range = selectionRangeRef.current;
         if (range) {
             const fragment = range.createContextualFragment(resultHtml);
             range.deleteContents();
             range.insertNode(fragment);
             const selection = window.getSelection();
             selection?.removeAllRanges();
         }
      }
      setRewriteModalOpen(false);
      if (editorRef.current) {
        const rawContent = getCurrentHtml();
        setGeneratedHtml(rawContent);
        pushToHistory(rawContent);
        saveToStorage();
      }
    } catch (error) {
      if (!isResettingRef.current) {
        console.error("Rewrite failed:", error);
        alert("Failed. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) setIsRewriting(false);
    }
  };

  // --- 5. PDF EXPORT ---
  const handleExportPDF = () => {
    if (!generatedHtml) return;
    const contentToPrint = isEditing && editorRef.current ? getCleanHtml() : generatedHtml;
    const printWindow = window.open('', '_blank');
    if (!printWindow) { alert("Enable pop-ups."); return; }

    // Using strict print CSS embedded here for the popup
    const content = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
          <meta charset="UTF-8">
          <title>Export Notes</title>
          <link href="https://fonts.googleapis.com/css2?family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Inter:wght@400;600;800&display=swap" rel="stylesheet">
          <style>
              @page { size: A4; margin: 5mm; }
              body { font-family: 'Merriweather', serif; font-size: 10pt; line-height: 1.4; color: #000; background: white; margin: 0; padding: 0; }
              h1 { font-family: 'Inter', sans-serif; font-size: 20pt; font-weight: 800; color: #000; border-bottom: 3px solid #000; padding-bottom: 5px; margin-top: 0; margin-bottom: 15px; page-break-after: avoid; }
              h2 { font-family: 'Inter', sans-serif; font-size: 14pt; font-weight: 700; color: #000; margin-top: 15px; margin-bottom: 8px; page-break-after: avoid; border-bottom: 1px solid #ddd; }
              h3 { font-family: 'Inter', sans-serif; font-size: 12pt; font-weight: 600; color: #000; margin-top: 10px; margin-bottom: 5px; page-break-after: avoid; }
              p { margin-bottom: 8px; text-align: justify; }
              ul, ol { margin-bottom: 10px; padding-left: 20px; }
              li { margin-bottom: 2px; }
              table { width: 100%; border-collapse: collapse; margin: 15px 0; border: 2px solid #000; page-break-inside: avoid; font-size: 9pt; }
              th { background-color: #f0f0f0; border: 1px solid #000; padding: 4px 8px; font-weight: bold; text-align: left; font-family: 'Inter', sans-serif; font-size: 9pt; }
              td { border: 1px solid #000; padding: 4px 8px; font-size: 9pt; vertical-align: top; }
              .flowchart-container { display: flex; justify-content: center; margin: 15px 0; padding: 5px; border: 1px dashed #ccc; page-break-inside: avoid; }
              svg { max-width: 100%; height: auto; }
              @media print {
                  body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                  .no-print { display: none; }
                  h1, h2, h3 { page-break-after: avoid; }
                  table, .flowchart-container { page-break-inside: avoid; }
                  p { orphans: 3; widows: 3; }
              }
          </style>
      </head>
      <body>
          ${contentToPrint}
          <script>
              window.onload = function() { setTimeout(function() { window.print(); }, 800); }
          </script>
      </body>
      </html>
    `;
    printWindow.document.open();
    printWindow.document.write(content);
    printWindow.document.close();
  };

  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setGeneratedHtml(history[newIndex]);
      setHistoryIndex(newIndex);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setGeneratedHtml(history[newIndex]);
      setHistoryIndex(newIndex);
    }
  };

  // --- RENDER ---
  return (
    <div className="flex h-screen w-full bg-gray-100 text-gray-900 font-sans overflow-hidden">

      {/* --- SIDEBAR (INPUT) --- */}
      <aside 
        className={`${sidebarOpen ? 'w-full md:w-96 translate-x-0' : 'w-0 -translate-x-full'} 
          fixed md:relative z-30 h-full bg-[#1e293b] text-white transition-all duration-300 ease-in-out flex flex-col border-r border-gray-700 shadow-2xl`}
      >
        <div className="p-5 border-b border-gray-700 flex items-center justify-between">
            <div className="flex items-center gap-3">
                <BookOpen className="w-6 h-6 text-blue-400" />
                <h1 className="text-xl font-bold tracking-tight">AI Book Writer</h1>
            </div>
            <button onClick={() => setSidebarOpen(false)} className="md:hidden text-gray-400 hover:text-white">
                <PanelLeftClose className="w-5 h-5"/>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-5 scrollbar-thin scrollbar-thumb-gray-600">
            {/* TABS */}
            <div className="flex bg-slate-800 p-1 rounded-lg mb-6 border border-slate-700">
                <button 
                   onClick={() => setMode('topic')}
                   className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm font-medium transition-all ${mode === 'topic' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
                >
                    <Sparkles className="w-4 h-4" /> Topic
                </button>
                <button 
                   onClick={() => setMode('text')}
