                </div>
            </div>
        </div>

        <div className="p-4 bg-slate-900 border-t border-slate-800 text-xs text-slate-500 text-center">
            AI Book Writer v2.0
        </div>
      </aside>

      {/* --- MAIN AREA (EDITOR) --- */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">

         {/* TOP TOOLBAR */}
         <div className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm z-20">
             <div className="flex items-center gap-4">
                 <button 
                   onClick={() => setSidebarOpen(!sidebarOpen)}
                   className="p-2 rounded-lg hover:bg-gray-100 text-gray-600 transition-colors"
                 >
                    {sidebarOpen ? <PanelLeftClose className="w-5 h-5" /> : <PanelLeft className="w-5 h-5" />}
                 </button>
                 <div className="h-6 w-px bg-gray-300"></div>
                 <div className="flex items-center gap-1 bg-gray-100 rounded-md p-1">
                    <button onClick={handleUndo} disabled={historyIndex <= 0} className="p-1.5 rounded hover:bg-white hover:shadow-sm text-gray-600 disabled:opacity-30"><Undo className="w-4 h-4"/></button>
                    <button onClick={handleRedo} disabled={historyIndex >= history.length - 1} className="p-1.5 rounded hover:bg-white hover:shadow-sm text-gray-600 disabled:opacity-30"><Redo className="w-4 h-4"/></button>
                 </div>
             </div>

             <div className="flex items-center gap-3">
                {isEditing ? (
                  <>
                     <Button variant="ghost" onClick={openSelectionRewriteModal} className="text-purple-600 bg-purple-50 hover:bg-purple-100 border-purple-200">
                        <Wand2 className="w-4 h-4 mr-2" /> Rewrite
                     </Button>
                     <Button variant="primary" onClick={() => { setIsEditing(false); saveToStorage(); }} className="bg-green-600 hover:bg-green-700">
