             <div className={`w-full max-w-[210mm] transition-all duration-500 ${!generatedHtml && status === GenerationStatus.IDLE ? 'opacity-50' : 'opacity-100'}`}>
                 <div className="editor-container a4-page shadow-xl editor-content bg-white min-h-[297mm]">
