                            onBlur={handleEditorBlur}
                            dangerouslySetInnerHTML={{ __html: generatedHtml || '' }}
                        />
                    )}
                 </div>
                 <div className="h-12"></div> {/* Bottom spacer */}
             </div>
         </div>

      </main>

      {/* --- REWRITE MODAL --- */}
      {rewriteModalOpen && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
           <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in duration-200">
              <div className="flex items-center justify-between mb-4">
                 <h3 className="text-lg font-bold flex items-center gap-2 text-gray-800">
                    {rewriteType === 'section' ? <Sparkles className="w-5 h-5 text-blue-600"/> : <Wand2 className="w-5 h-5 text-purple-600"/>}
