              <div className="mb-4 text-sm text-gray-500 bg-gray-50 p-3 rounded-lg border border-gray-100 max-h-32 overflow-y-auto">
                 <strong>Context:</strong>
                 <div className="italic mt-1 text-xs opacity-70">
                    {rewriteType === 'section' ? "Selected Section" : selectionRangeRef.current?.toString().substring(0, 100) + "..."}
                 </div>
              </div>

              <form onSubmit={handleRewriteSubmit}>
                 <label className="block text-sm text-gray-600 mb-2">Instruction</label>
                 <input 
                   type="text" 
                   value={rewriteInstruction}
