import { GoogleGenAI } from "@google/genai";

export const createAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to clean AI output
const cleanHtmlOutput = (text: string): string => {
  if (!text) return "";
  // Remove markdown code blocks (```html ... ```)
  return text
    .replace(/^```html\s*/i, '') // Remove start block
    .replace(/^```\s*/i, '')     // Remove start block generic
    .replace(/\s*```$/i, '')      // Remove end block
    .trim();                      // Trim whitespace
};

// Generate Detailed Content directly from a Topic
export const generateTopicContent = async (
  topic: string,
  language: string
): Promise<string> => {
  const ai = createAIClient();

  const prompt = `
    You are an expert educational content creator and book writer.
    **Topic:** "${topic}"
    **Language:** ${language}

    **Goal:** Write a high-quality, professional study guide or chapter.

    **Formatting Rules (Strict HTML):**
    1. **Structure:** Use <h1> for main title, <h2> for sections, <h3> for sub-sections.
    2. **Key Concepts:** Wrap vital definitions in: 
       <div class="key-point"><strong>Key Concept:</strong> ...content...</div>
    3. **Important Notes:** Wrap extra tips or remarks in the **Yellow Note Box**:
       <div class="note-box">...content...</div>
    4. **Tables:** Create detailed comparison tables with <thead> (Use styling rules implied).

    **Visualizations (Crucial):**
    Create at least one **Professional SVG Diagram** inside a <div class="flowchart-container"> based on the content type:

    *   **IF HISTORICAL/SEQUENCE:** Create a **Horizontal Timeline**.
        - Draw a long horizontal line (e.g., width="600").
        - Place distinct circles at intervals.
        - Put text labels *below* or *above* the circles.
        - Use distinct colors (e.g., blue circles, slate text).

    *   **IF HIERARCHICAL:** Create a **Tree Diagram**.
        - Top-down structure (Root -> Branches -> Leaves).
        - Use lines/paths to connect boxes.
        - Style boxes with rounded corners (rx="4") and light blue fill.

    *   **IF CONCEPTUAL:** Create a **Mind Map**.
        - Central idea in the middle.
        - Branches radiating outwards to sub-concepts.
        - Use different stroke colors for branches.

    **SVG Styling Rules:**
    - Use clear fonts (font-family="sans-serif").
    - Ensure text is readable (no overlapping).
    - Use a professional color palette (Blues, Teals, Slate).

    **Output:** Return ONLY raw HTML. No markdown formatting.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", 
    contents: prompt,
  });

  return cleanHtmlOutput(response.text || "");
};

