import { GoogleGenAI } from "@google/genai";

export const createAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to clean AI output
const cleanHtmlOutput = (text: string): string => {
  if (!text) return "";
  // Remove markdown code blocks (```html ... ```)
  return text
    .replace(/^```html\s*/i, '') // Remove start block
    .replace(/^```\s*/i, '')     // Remove start block generic
    .replace(/\s*```$/i, '')      // Remove end block
    .trim();                      // Trim whitespace
};

// Generate Detailed Content directly from a Topic
export const generateTopicContent = async (
  topic: string,
  language: string
): Promise<string> => {
  const ai = createAIClient();

  const prompt = `
    You are an expert educational content creator and book writer.
    **Topic:** "${topic}"
    **Language:** ${language}

    **Goal:** Write a high-quality, professional study guide or chapter.

    **Formatting Rules (Strict HTML):**
    1. **Structure:** Use <h1> for main title, <h2> for sections, <h3> for sub-sections.
    2. **Key Concepts:** Wrap vital definitions in: 
       <div class="key-point"><strong>Key Concept:</strong> ...content...</div>
    3. **Important Notes:** Wrap extra tips or remarks in the **Yellow Note Box**:
       <div class="note-box">...content...</div>
    4. **Tables:** Create detailed comparison tables with <thead> (Use styling rules implied).

    **Visualizations (Crucial):**
    Create at least one **Professional SVG Diagram** inside a <div class="flowchart-container">. Choose the MOST appropriate type:

    *   **IF PROCESS/LOGIC:** Create a **Flowchart**.
        - Use standard symbols: Rectangles (Process), Diamonds (Decision), Ovals (Start/End).
        - Connect with directional arrows.
        - Use soft fill colors (e.g., #e0f2fe for process, #fef3c7 for decision).

    *   **IF HISTORICAL/SEQUENCE:** Create a **Horizontal Timeline**.
        - Draw a long horizontal line (e.g., width="600").
        - Place distinct circles at intervals.
        - Put text labels *below* or *above* the circles.
        - Use distinct colors (e.g., blue circles, slate text).

    *   **IF HIERARCHICAL/STRUCTURAL:** Create an **Organizational Chart** or **Tree Diagram**.
        - Top-down structure (Root -> Branches -> Leaves).
        - Use lines/paths to connect boxes.
        - Style boxes with rounded corners (rx="4") and light blue fill.

    *   **IF CONCEPTUAL/CLUSTERS:** Create a **Mind Map**.
        - Central idea in the middle.
        - Branches radiating outwards to sub-concepts.
        - Use different stroke colors for branches.

    *   **IF SYSTEM/DATA:** Create a **Data Flow Diagram**.
        - Entities as rectangles, processes as rounded shapes.
        - Arrows showing information flow direction.

    **SVG Styling Rules:**
    - Use clear fonts (font-family="sans-serif").
    - Ensure text is readable (no overlapping).
    - Use a professional color palette (Blues, Teals, Slate).

    **Output:** Return ONLY raw HTML. No markdown formatting.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", 
    contents: prompt,
  });

  return cleanHtmlOutput(response.text || "");
};

// Generate Structured Notes from Raw Text
export const generateFormattedNotes = async (
  rawText: string,
  language: string
): Promise<string> => {
  const ai = createAIClient();

  const prompt = `
    You are an expert formatter and study guide creator. 
    **Task:** Transform the raw text into a structured, high-quality document.
    **Language:** ${language}

    **Input Text:** ${rawText}

    **Requirements:**
    1. **Hierarchy:** Use <h1>, <h2>, <h3>.
    2. **Yellow Notes:** Highlight important tips/facts in <div class="note-box">...</div>.
    3. **Key Points:** Use <div class="key-point"> for formal definitions.
    4. **Tables:** Convert data into HTML tables.

    **Visuals:** 
    - Identify the structure of the information and generate the appropriate SVG diagram inside <div class="flowchart-container">:
      - **Flowchart** for processes, algorithms, or step-by-step logic.
      - **Timeline (Horizontal)** for history, dates, or sequences.
      - **Tree Diagram/Org Chart** for hierarchy, categorization, or structure.
      - **Mind Map** for brainstorming, concepts, or clusters.
      - **Data Flow Diagram** for systems or interactions.
    - Make the SVG visually appealing with colors and clean lines.

    **Output:** Return ONLY raw HTML.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
  });

  return cleanHtmlOutput(response.text || "");
};

// Rewrite specific text selection
export const rewriteContent = async (
    textToRewrite: string,
    instruction: string
  ): Promise<string> => {
    const ai = createAIClient();

    const prompt = `
      You are an expert editor.
      **Input:** "${textToRewrite}"
      **Instruction:** ${instruction}

      **Task:** Rewrite the text to be clearer and more professional.
      **Formatting:** 
      - Use <div class="key-point"> for definitions.
      - Use <div class="note-box"> for tips or interesting facts.

      Return ONLY the HTML fragment.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });

    return cleanHtmlOutput(response.text || textToRewrite);
};

// Mode 1: REWRITE (Small edits)
export const rewriteSection = async (
  sectionContent: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();
  const prompt = `
    You are an expert editor.
    **Task:** Rewrite the HTML section below based on the instruction.
    **Constraint:** Keep the structure valid.
    **Features:**
    - You can add a <div class="note-box"> if the user asks to highlight something.
    - You can add a <div class="key-point"> for emphasis.

    **HTML:** ${sectionContent}
    **Instruction:** "${instruction}"

    **Output:** Return ONLY the valid HTML.
  `;
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
  });
  return cleanHtmlOutput(response.text || "");
};

// Mode 2: EXPAND (Deep Dive)
export const expandSection = async (
  sectionContent: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();
  const prompt = `
    You are an expert book writer.
    **Task:** EXPAND the following section into a detailed explanation.

    **Input HTML:**
    ${sectionContent}

    **Instruction:** "${instruction}"

    **Rules:**
    - Add concrete examples.
    - Add a **Comparison Table** if applicable.
    - Add a **Yellow Note** (<div class="note-box">) for "Did you know?" or tips.
    - Maintain professional tone.

    **Output:** Return ONLY the valid HTML.
  `;
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
  });
  return cleanHtmlOutput(response.text || "");
};

// Mode 3: CONTINUE (Add next content)
export const generateNextContent = async (
  previousContext: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();
  const prompt = `
    You are an expert book writer.
    **Context:** The user wants to continue writing AFTER this section.

    **Previous Section:**
    ${previousContext}

    **Instruction:** "${instruction}"

    **Task:** Write the NEXT logical content.
    - Use <h2> for new sections.
    - Include a **Yellow Note** (<div class="note-box">) if summarizing.
    - If a new process is introduced, include a brief SVG diagram description or the SVG itself.

    **Output:** Return ONLY the HTML for the NEW content.
  `;
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
  });
  return cleanHtmlOutput(response.text || "");
};

// Mode 4: GENERATE IMAGE (Nano Banana)
export const generateSectionImage = async (
  contextText: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();

  // Clean context to remove tags for better prompting
  const cleanContext = contextText.replace(/<[^>]+>/g, ' ').substring(0, 1000);

  const prompt = `
    Create a professional, educational illustration/diagram for a textbook.

    **Context:** ${cleanContext}

    **Specific Instruction:** ${instruction || "Illustrate the key concept of this section."}

    **Style:** Clean, academic, high contrast. suitable for a study guide.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
        parts: [
            { text: prompt }
        ]
    }
  });

  let imageUrl = "";
  if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
              imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
              break;
          }
      }
  }

  if (!imageUrl) {
      throw new Error("No image generated");
  }

  // Return HTML for the image
  return `
    <figure>
        <img src="${imageUrl}" alt="Generated Illustration" />
        <figcaption>Figure: Illustration generated by AI based on section context.</figcaption>
    </figure>
  `;
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  generateTopicContent, 
  generateFormattedNotes, 
  rewriteContent, 
  rewriteSection,
  expandSection,
  generateNextContent,
  generateSectionImage
} from './services/ai';
import { GenerationStatus } from './types';
import { Button } from './components/Button';
import { 
  BookOpen, 
  PenTool, 
  Printer, 
  Sparkles,
  FileText,
  Trash2,
  Wand2,
  ArrowLeft,
  Check,
  Save,
  Undo,
  Redo,
  RefreshCw,
  Plus,
  PanelLeftClose,
  PanelLeft,
  Download,
  Eraser,
  Settings,
  Image as ImageIcon
} from 'lucide-react';

const STORAGE_KEY = 'ai_book_writer_draft';

const App: React.FC = () => {
  // --- UI STATE ---
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // --- GENERATION STATE ---
  const [mode, setMode] = useState<'topic' | 'text'>('topic');
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [language, setLanguage] = useState('Hindi'); 
  const [topicInput, setTopicInput] = useState('');
  const [textInput, setTextInput] = useState('');

  // --- EDITOR STATE ---
  const [isEditing, setIsEditing] = useState(false);
  const [generatedHtml, setGeneratedHtml] = useState<string | null>(null);
  const editorRef = useRef<HTMLDivElement>(null);

  // --- HISTORY STATE ---
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const historyTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // --- REWRITE STATE ---
  const isResettingRef = useRef(false);
  const [rewriteModalOpen, setRewriteModalOpen] = useState(false);
  const [rewriteInstruction, setRewriteInstruction] = useState('');
  const [isRewriting, setIsRewriting] = useState(false);
  const selectionRangeRef = useRef<Range | null>(null);
  const activeEditIdRef = useRef<string | null>(null);
  const [activeSectionHtml, setActiveSectionHtml] = useState<string>('');
  const [rewriteType, setRewriteType] = useState<'selection' | 'section'>('selection');
  const [editTab, setEditTab] = useState<'rewrite' | 'expand' | 'continue' | 'image'>('rewrite');

  // --- 1. INITIALIZATION & HISTORY ---

  const pushToHistory = useCallback((content: string) => {
    setHistory(prev => {
      if (historyIndex >= 0 && prev[historyIndex] === content) return prev;
      const newHistory = prev.slice(0, historyIndex + 1);
      return [...newHistory, content];
    });
    setHistoryIndex(prev => prev + 1);
  }, [historyIndex]);

  useEffect(() => {
    const savedContent = localStorage.getItem(STORAGE_KEY);
    if (savedContent) {
      setGeneratedHtml(savedContent);
      setHistory([savedContent]);
      setHistoryIndex(0);
    }
  }, []);

  // --- 2. EDITOR HELPERS ---

  const getCurrentHtml = useCallback(() => {
    return editorRef.current ? editorRef.current.innerHTML : (generatedHtml || '');
  }, [generatedHtml]);

  const getCleanHtml = useCallback(() => {
    if (!editorRef.current) return generatedHtml || '';
    const clone = editorRef.current.cloneNode(true) as HTMLElement;
    clone.querySelectorAll('.ai-edit-trigger').forEach(b => b.remove());
    clone.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    return clone.innerHTML;
  }, [generatedHtml]);

  const saveToStorage = useCallback(() => {
    if (isResettingRef.current) return;
    const content = getCleanHtml();
    if (content) {
      localStorage.setItem(STORAGE_KEY, content);
    }
    return content;
  }, [getCleanHtml]);

  // Sync content state to DOM without resetting cursor during edits
  useEffect(() => {
    if (editorRef.current) {
        // Only update DOM if the new generatedHtml is logically different
        // This prevents re-renders from killing the cursor position during typing
        if (editorRef.current.innerHTML !== (generatedHtml || '')) {
             editorRef.current.innerHTML = generatedHtml || '';
        }
    }
  }, [generatedHtml]);

  // Auto-save logic
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'hidden') saveToStorage();
    };
    const intervalId = setInterval(() => { if (isEditing) saveToStorage(); }, 5000);
    window.addEventListener('visibilitychange', handleVisibilityChange);
    window.addEventListener('pagehide', saveToStorage);
    window.addEventListener('beforeunload', saveToStorage);
    return () => {
      window.removeEventListener('visibilitychange', handleVisibilityChange);
      window.removeEventListener('pagehide', saveToStorage);
      window.removeEventListener('beforeunload', saveToStorage);
      clearInterval(intervalId);
    };
  }, [saveToStorage, isEditing]);

  const handleEditorInput = () => {
    if (isResettingRef.current) return;
    if (historyTimeoutRef.current) clearTimeout(historyTimeoutRef.current);
    historyTimeoutRef.current = setTimeout(() => {
       if (isResettingRef.current) return;
       const rawContent = getCurrentHtml(); 
       // Only update state if content actually changed
       if (rawContent !== generatedHtml) {
           setGeneratedHtml(rawContent); 
           pushToHistory(rawContent);
           saveToStorage();
       }
    }, 800);
  };

  const handleEditorBlur = () => {
      if (isResettingRef.current) return;
      const rawContent = getCurrentHtml();
      setGeneratedHtml(rawContent);
  };

  // --- 3. CORE GENERATION LOGIC ---

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'topic' && !topicInput.trim()) return;
    if (mode === 'text' && !textInput.trim()) return;

    setStatus(GenerationStatus.GENERATING_CHAPTER);

    try {
      let result = "";
      if (mode === 'topic') {
        result = await generateTopicContent(topicInput, language);
      } else {
        result = await generateFormattedNotes(textInput, language);
      }

      if (isResettingRef.current) return;

      setGeneratedHtml(result);
      pushToHistory(result);
      localStorage.setItem(STORAGE_KEY, result); 

      // On mobile, auto-close sidebar after generation for better UX
      if (window.innerWidth < 768) {
          setSidebarOpen(false);
      }

    } catch (error) {
      if (!isResettingRef.current) {
        console.error(error);
        alert("Error generating content. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) {
        setStatus(GenerationStatus.IDLE);
      }
    }
  };

  const handleClearCanvas = () => {
    if(!confirm("Are you sure you want to clear the editor?")) return;
    isResettingRef.current = true;
    setGeneratedHtml(null);
    setHistory([]);
    setHistoryIndex(-1);
    setIsEditing(false);
    activeEditIdRef.current = null;
    selectionRangeRef.current = null;
    localStorage.removeItem(STORAGE_KEY);
    setTimeout(() => { isResettingRef.current = false; }, 100);
  };

  // --- 4. REWRITE & EDIT LOGIC ---
  // (Helper for edit buttons)
  const getSectionNodes = (startNode: Element): Element[] => {
    const nodes: Element[] = [startNode];
    const tagName = startNode.tagName;
    const getLevel = (tag: string) => {
      const t = tag.toUpperCase();
      if (t === 'H1') return 1;
      if (t === 'H2') return 2;
      if (t === 'H3') return 3;
      if (t === 'H4') return 4;
      return 10; 
    };
    const currentLevel = getLevel(tagName);
    if (currentLevel <= 4) {
      let nextSibling = startNode.nextElementSibling;
      while (nextSibling) {
        const nextTag = nextSibling.tagName;
        const nextLevel = getLevel(nextTag);
        if (nextLevel <= currentLevel) break;
        nodes.push(nextSibling);
        nextSibling = nextSibling.nextElementSibling;
      }
    } 
    return nodes;
  };

  useEffect(() => {
    if (!editorRef.current) return;
    if (isEditing) {
      const elements = editorRef.current.querySelectorAll('h1, h2, h3, h4, li');
      elements.forEach((el) => {
        if (el.querySelector('.ai-edit-trigger')) return;
        const btn = document.createElement('span');
        btn.contentEditable = "false";
        btn.className = "ai-edit-trigger no-print";
        btn.innerHTML = "✨";
        btn.title = "Rewrite/Expand";
        if (el.tagName === 'LI') el.insertBefore(btn, el.firstChild);
        else el.appendChild(btn);
      });
    } else {
      editorRef.current.querySelectorAll('.ai-edit-trigger').forEach(btn => btn.remove());
    }
  }, [isEditing, generatedHtml]);

  useEffect(() => {
    const handleEditorClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (target.classList.contains('ai-edit-trigger')) {
        e.preventDefault();
        e.stopPropagation();
        const parentEl = target.parentElement;
        if (parentEl) handleSectionEdit(parentEl);
      }
    };
    const editor = editorRef.current;
    if (editor) editor.addEventListener('click', handleEditorClick);
    return () => { if (editor) editor.removeEventListener('click', handleEditorClick); };
  }, [isEditing]);

  const handleSectionEdit = (startNode: Element) => {
    if (!editorRef.current) return;
    const currentRaw = getCurrentHtml();
    pushToHistory(currentRaw);
    setGeneratedHtml(currentRaw);

    const editId = `edit-${Date.now()}`;
    editorRef.current.querySelectorAll('[data-edit-id]').forEach(el => el.removeAttribute('data-edit-id'));
    startNode.setAttribute('data-edit-id', editId);
    activeEditIdRef.current = editId;

    const nodes = getSectionNodes(startNode);
    const tempDiv = document.createElement('div');
    nodes.forEach(node => {
        const clone = node.cloneNode(true) as Element;
        const trigger = clone.querySelector('.ai-edit-trigger');
        if(trigger) trigger.remove();
        clone.removeAttribute('data-edit-id'); 
        tempDiv.appendChild(clone);
    });
    setActiveSectionHtml(tempDiv.innerHTML);
    setGeneratedHtml(editorRef.current.innerHTML); 
    setRewriteType('section');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const openSelectionRewriteModal = () => {
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.toString().trim().length === 0) {
      alert("Please select text to rewrite.");
      return;
    }
    selectionRangeRef.current = selection.getRangeAt(0);
    setRewriteType('selection');
    setEditTab('rewrite');
    setRewriteInstruction('');
    setRewriteModalOpen(true);
  };

  const handleRewriteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsRewriting(true);
    try {
      const rawBefore = getCurrentHtml();
      pushToHistory(rawBefore);
      let resultHtml = "";

      if (rewriteType === 'section') {
         if (editTab === 'rewrite') resultHtml = await rewriteSection(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'expand') resultHtml = await expandSection(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'continue') resultHtml = await generateNextContent(activeSectionHtml, rewriteInstruction);
         else if (editTab === 'image') {
             const imgHtml = await generateSectionImage(activeSectionHtml, rewriteInstruction);
             resultHtml = activeSectionHtml + imgHtml;
         }
      } else {
         const selectedText = selectionRangeRef.current?.toString() || "";
         if (editTab === 'rewrite') resultHtml = await rewriteContent(selectedText, rewriteInstruction);
         else if (editTab === 'expand') resultHtml = await expandSection(selectedText, rewriteInstruction);
         else if (editTab === 'continue') {
             const nextContent = await generateNextContent(selectedText, rewriteInstruction);
             resultHtml = selectedText + " " + nextContent;
         } else if (editTab === 'image') {
             const imgHtml = await generateSectionImage(selectedText, rewriteInstruction);
             // For selection, we append the image after the text
             resultHtml = selectedText + "<br/>" + imgHtml;
         }
      }

      if (isResettingRef.current) return;
      if (!resultHtml) throw new Error("No content generated");

      // DOM Replacement Logic
      if (rewriteType === 'section') {
         const editId = activeEditIdRef.current;
         if (!editorRef.current || !editId) throw new Error("Editor context lost.");
         const startNode = editorRef.current.querySelector(`[data-edit-id="${editId}"]`);
         if (!startNode) throw new Error("Lost position.");
         const nodesToReplace = getSectionNodes(startNode);
         const firstNode = nodesToReplace[0];
         const lastNode = nodesToReplace[nodesToReplace.length - 1];
         const parent = firstNode.parentNode;
         if (!parent) throw new Error("Parent node lost.");

         const range = document.createRange();
         range.setStartBefore(firstNode);
         const fragment = range.createContextualFragment(resultHtml);

         if (editTab === 'continue') {
            if (lastNode.nextSibling) parent.insertBefore(fragment, lastNode.nextSibling);
            else parent.appendChild(fragment);
            startNode.removeAttribute('data-edit-id');
         } else {
            parent.insertBefore(fragment, firstNode);
            nodesToReplace.forEach(n => n.remove());
         }
      } else {
         const range = selectionRangeRef.current;
         if (range) {
             const fragment = range.createContextualFragment(resultHtml);
             range.deleteContents();
             range.insertNode(fragment);
             const selection = window.getSelection();
             selection?.removeAllRanges();
         }
      }
      setRewriteModalOpen(false);
      if (editorRef.current) {
        const rawContent = getCurrentHtml();
        setGeneratedHtml(rawContent);
        pushToHistory(rawContent);
        saveToStorage();
      }
    } catch (error) {
      if (!isResettingRef.current) {
        console.error("Rewrite failed:", error);
        alert("Failed. Please try again.");
      }
    } finally {
      if (!isResettingRef.current) setIsRewriting(false);
    }
  };

  // --- 5. PDF EXPORT ---
  const handleExportPDF = () => {
    if (!generatedHtml) return;
    const contentToPrint = isEditing && editorRef.current ? getCleanHtml() : generatedHtml;
    const printWindow = window.open('', '_blank');
    if (!printWindow) { alert("Enable pop-ups."); return; }

    const content = `
      <!DOCTYPE html>
      <html lang="en">
      <head>
          <meta charset="UTF-8">
          <title>Export Notes</title>
          <link href="https://fonts.googleapis.com/css2?family=Merriweather:ital,wght@0,300;0,400;0,700;1,400&family=Inter:wght@400;600;800&display=swap" rel="stylesheet">
          <style>
              @page { size: A4; margin: 5mm; }
              body { font-family: 'Merriweather', serif; font-size: 11pt; line-height: 1.6; color: #1e293b; background: white; margin: 0; padding: 0; }
              h1 { font-family: 'Inter', sans-serif; font-size: 24pt; font-weight: 800; color: #0f172a; border-bottom: 3px solid #0f172a; padding-bottom: 10px; margin-top: 0; margin-bottom: 20px; page-break-after: avoid; }
              h2 { font-family: 'Inter', sans-serif; font-size: 16pt; font-weight: 700; color: #1e3a8a; margin-top: 24px; margin-bottom: 12px; page-break-after: avoid; border-bottom: 1px solid #e2e8f0; }
              h3 { font-family: 'Inter', sans-serif; font-size: 13pt; font-weight: 600; color: #334155; margin-top: 18px; margin-bottom: 8px; page-break-after: avoid; }
              p { margin-bottom: 12px; text-align: justify; }
              ul, ol { margin-bottom: 16px; padding-left: 24px; }
              li { margin-bottom: 6px; }
              strong { color: #0f172a; font-weight: 700; }
              .key-point { background-color: #f8fafc; border-left: 4px solid #3b82f6; padding: 16px; margin: 20px 0; font-family: 'Inter', sans-serif; font-size: 0.95em; page-break-inside: avoid; }

              /* FORCE BLACK BORDERS ON PRINT */
              table { width: 100%; border-collapse: collapse; margin: 20px 0; border: 2px solid #000 !important; page-break-inside: avoid; font-size: 9.5pt; }
              th { background-color: #1e293b !important; color: white !important; padding: 10px; font-weight: 600; text-align: left; font-family: 'Inter', sans-serif; border: 1px solid #000 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
              td { border: 1px solid #000 !important; padding: 10px; vertical-align: top; }
              tr:nth-child(even) { background-color: #f8fafc; -webkit-print-color-adjust: exact; print-color-adjust: exact; }

              .flowchart-container { display: flex; justify-content: center; margin: 24px 0; padding: 10px; border: 1px solid #e2e8f0; page-break-inside: avoid; }
              svg { max-width: 100%; height: auto; }

              /* IMAGE PRINT STYLES */
              figure { margin: 20px 0; text-align: center; page-break-inside: avoid; }
              img { max-width: 100%; height: auto; border: 1px solid #ccc; }
              figcaption { font-size: 0.9em; color: #666; font-style: italic; margin-top: 5px; }

              @media print {
                  body { padding: 0; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                  .no-print { display: none; }
                  h1, h2, h3 { page-break-after: avoid; }
                  table, .flowchart-container, .key-point, figure, img { page-break-inside: avoid; }
                  p { orphans: 3; widows: 3; }
              }
          </style>
      </head>
      <body>
          ${contentToPrint}
          <script>
              window.onload = function() { setTimeout(function() { window.print(); }, 800); }
          </script>
      </body>
      </html>
    `;
    printWindow.document.open();
    printWindow.document.write(content);
    printWindow.document.close();
  };

