import { GoogleGenAI } from "@google/genai";

export const createAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to clean AI output
const cleanHtmlOutput = (text: string): string => {
  if (!text) return "";
  // Remove markdown code blocks (```html ... ```)
  return text
    .replace(/^```html\s*/i, '') // Remove start block
    .replace(/^```\s*/i, '')     // Remove start block generic
    .replace(/\s*```$/i, '')      // Remove end block
    .trim();                      // Trim whitespace
};

// Generate Detailed Content directly from a Topic
export const generateTopicContent = async (
  topic: string,
  language: string
): Promise<string> => {
  const ai = createAIClient();

  const prompt = `
    Role: Academic Textbook Author & Subject Matter Expert.
    Task: Write an EXHAUSTIVE, DEEP-DIVE chapter.
    Model Config: Use maximum output tokens. Do not summarize.

    Topic: "${topic}"
    Language: ${language}

    **STRICT NUMBERING & STRUCTURE RULES:**
    You must use a strict hierarchical numbering system for ALL headings.
    - <h1>1. [Main Title]</h1>
    - <h2>1.1 [Major Section]</h2>
    - <h3>1.1.1 [Sub-Section]</h3>
    - <h4>1.1.1.1 [Detailed Point]</h4>

    **CONTENT REQUIREMENTS:**
    1. **Volume:** Write extensive paragraphs. Explain "Why", "How", "When", and "What".
    2. **Depth:** Go into minute details. Every sub-section (1.1.1) must have at least 300 words.
    3. **Key Concepts:** Wrap vital definitions in: <div class="key-point"><strong>Key Concept:</strong> ...text...</div>
    4. **Notes:** Use <div class="note-box">...text...</div> for extra facts.
    5. **Tables:** Use strict HTML tables with <thead> and black borders for complex data comparisons.

    **VISUALIZATION LOGIC (Mandatory):**
    Analyze the topic and generate ONE detailed SVG diagram inside <div class="flowchart-container">.
    - If logic/process: Flowchart (Rectangles/Diamonds).
    - If history: Timeline (Horizontal line with circles).
    - If structure: Tree Diagram (Top-down hierarchy).
    - If comparison: Venn Diagram or Matrix.
    *Style:* Professional, clean, educational colors (Blues/Grays).

    **Output:** Return ONLY raw HTML.
  `;

  // Using gemini-3-pro-preview with high thinking budget for complex structuring
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview", 
    contents: prompt,
    config: {
        thinkingConfig: { thinkingBudget: 2048 } // Allow model to plan the hierarchy
    }
  });

  return cleanHtmlOutput(response.text || "");
};

// Generate Structured Notes from Raw Text
export const generateFormattedNotes = async (
