export const generateSectionImage = async (
  contextText: string,
  instruction: string
): Promise<string> => {
  const ai = createAIClient();

  const cleanContext = contextText
    .replace(/<h[1-6][^>]*>(.*?)<\/h[1-6]>/gi, '\nHEAD: $1\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
