      setHistoryIndex(newIndex);
    }
  };

  // --- RENDER ---
  return (
    <div className="flex h-screen w-full bg-gray-50 text-gray-900 font-sans overflow-hidden dot-pattern">

      {/* --- SIDEBAR (INPUT) --- */}
      <aside 
        className={`${sidebarOpen ? 'w-full md:w-[400px]' : 'w-0'} 
